"use client";

import React from "react";
import {
  AnimatedToggleGroup,
  AnimatedToggleItem,
} from "@/components/ui/motion/animated-toggle-group";
import { useUiPreferences } from "@/hooks/use-ui-preferences";
import { RADIUS_MAP } from "@/constants/radius";
import type { RadiusKey } from "@/types/ui-preferences";

const radiusKeys = Object.keys(RADIUS_MAP) as RadiusKey[];

export function RadiusSelector() {
  const radius = useUiPreferences((s) => s.radius);
  const setRadius = useUiPreferences((s) => s.setRadius);

  return (
    <AnimatedToggleGroup
      value={radius}
      onValueChange={(val) => setRadius(val as RadiusKey)}
    >
      {radiusKeys.map((key) => (
        <AnimatedToggleItem key={key} value={key}>
          <RadiusIcon radius={key} />
        </AnimatedToggleItem>
      ))}
    </AnimatedToggleGroup>
  );
}

interface RadiusIconProps {
  radius: RadiusKey;
}

function RadiusIcon({ radius }: RadiusIconProps) {
  const radiusValues = {
    sm: 3, // 6px
    md: 4, // 8px
    xl: 5, // 10px
    "3xl": 12, // 24px
  };

  const r = radiusValues[radius];

  if (radius === "3xl") {
    return (
      <svg
        className="size-6"
        viewBox="0 0 20 20"
        fill="var(--foreground)"
        fillOpacity="0.35"
        stroke="var(--foreground)"
        strokeWidth="1.5"
      >
        {/* Fill area - closed path */}
        <path
          d="M4 4 L4 4 Q4 16 16 16 L16 4 Z"
          fill="var(--foreground)"
          fillOpacity="0.35"
          stroke="none"
        />
        {/* Stroke outline */}
        <path
          d="M4 4 L4 4 Q4 16 16 16 L16 16"
          fill="none"
          stroke="var(--foreground)"
          strokeWidth="1.5"
          strokeLinecap="round"
          strokeLinejoin="round"
        />
      </svg>
    );
  }

  return (
    <svg
      className="size-6"
      viewBox="0 0 20 20"
      fill="var(--foreground)"
      stroke="var(--foreground)"
      strokeWidth="1.5"
    >
      {/* Fill area - closed path */}
      <path
        d={`M4 4 L4 ${16 - r} Q4 16 ${4 + r} 16 L16 16 L16 4 Z`}
        fill="var(--foreground)"
        fillOpacity="0.35"
        stroke="none"
      />
      {/* Stroke outline */}
      <path
        d={`M4 4 L4 ${16 - r} Q4 16 ${4 + r} 16 L16 16`}
        fill="none"
        stroke="var(--foreground)"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

import type { ControlsMap, PlaygroundProps } from "./types";

export function generateCode(
  componentPath: string,
  values: Record<string, React.ReactNode>,
  controls: ControlsMap,
  section: PlaygroundProps["section"]
) {
  const componentName = componentPath.split("/")[0];
  const capitalizedComponentName = componentName
    .split("-")
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join("");

  const imports = new Set<string>();
  imports.add(
    `import { ${capitalizedComponentName} } from "@/components/ui/${section}/${componentName}";`
  );

  let children =
    typeof values.children === "string"
      ? values.children
      : values.children
        ? `{${String(values.children)}}`
        : "";

  const props = Object.entries(values)
    .filter(([key, value]) => {
      if (key === "children") return false;

      const schema = controls[key];
      if (!schema) return false;

      const mappingKey = String(value);
      if (schema.mapping && schema.mapping[mappingKey]) {
        const { imports: mappedImports, children: mappedChildren } =
          schema.mapping[mappingKey];

        if (mappedImports) {
          mappedImports.forEach((imp) => imports.add(imp));
        }

        if (mappedChildren) {
          children = mappedChildren;
        }
      }

      if (value === schema.defaultValue) return false;
      return true;
    })
    .map(([key, value]) => {
      const schema = controls[key];

      if (schema?.type === "boolean") {
        return value ? key : null;
      }

      if (typeof value === "string") {
        return `${key}="${value}"`;
      }

      if (typeof value === "number") {
        return `${key}={${value}}`;
      }

      return `${key}={${JSON.stringify(value)}}`;
    })
    .filter(Boolean)
    .join(" ");

  const importStatements = Array.from(imports).join("\n");

  return `${importStatements}

export function Component() {
  return (
