"use client";

import { usePlayground } from "./playground-context";
import { Select } from "@/components/ui/core/select";
import { Switch } from "@/components/ui/core/switch";
import { Input } from "@/components/ui/core/input";
import { Label } from "@/components/ui/core/field";
import { NumberField, NumberInput } from "@/components/ui/core/number-field";
import { ToggleGroup, ToggleItem } from "@/components/ui/core/toggle-group";
import { TextField } from "@/components/ui/core/text-field";
import { Textarea } from "@/components/ui/core/text-area";

export function Controls() {
  const { controls, values, setValue } = usePlayground();

  if (!controls || Object.keys(controls).length === 0) {
    return (
      <div className="text-sm text-muted-foreground p-4 text-center">
        No controls available
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-4 p-1">
      {Object.entries(controls).map(([key, schema]) => {
        if (schema.type === "select" && schema.options) {
          return (
            <Select
              key={key}
              label={schema.label || key}
              selectedKey={values[key] as string | number}
              onSelectionChange={(k) => setValue(key, k ?? "")}
              items={schema.options.map((opt) => ({
                id: opt.value,
                label: opt.label,
              }))}
            />
          );
        }

        if (schema.type === "toggle-group" && schema.options) {
          return (
            <div key={key} className="flex flex-col gap-2">
              <Label className="capitalize">{schema.label || key}</Label>
              <ToggleGroup
                disallowEmptySelection
                selectionMode="single"
                selectedKeys={new Set([values[key] as string | number])}
                onSelectionChange={(selected) => {
                  const val = selected.values().next().value;
                  if (val !== undefined) setValue(key, val);
                }}
              >
                {schema.options.map((item) => (
                  <ToggleItem key={item.value} id={item.value}>
                    {item.label}
                  </ToggleItem>
                ))}
              </ToggleGroup>
            </div>
          );
        }

        if (schema.type === "boolean") {
          return (
            <div key={key} className="flex items-center justify-between">
              <Switch
                isSelected={values[key] as boolean}
                onChange={(v) => setValue(key, v)}
              >
                {schema.label || key}
              </Switch>
            </div>
          );
        }

        if (schema.type === "text") {
          return (
            <TextField
              key={key}
              value={(values[key] as string) || ""}
              onChange={(value) => setValue(key, value)}
            >
              <Label className="capitalize">{schema.label || key}</Label>
              <Input placeholder={schema.placeholder} />
            </TextField>
          );
        }

        if (schema.type === "textarea") {
          return (
            <TextField
              key={key}
              value={(values[key] as string) || ""}
              onChange={(value) => setValue(key, value)}
            >
              <Label className="capitalize">{schema.label || key}</Label>
              <Textarea placeholder={schema.placeholder} />
            </TextField>
          );
        }

        if (schema.type === "number") {
          return (
            <NumberField
              key={key}
              value={(values[key] as number) || 0}
              onChange={(val) => {
                setValue(key, isNaN(val) ? 0 : val);
              }}
              minValue={schema.min}
              maxValue={schema.max}
            >
              <Label className="capitalize">{schema.label || key}</Label>
              <NumberInput placeholder={schema.placeholder} />
            </NumberField>
          );
        }

        return null;
      })}
    </div>
  );
}

"use client";

import React, { createContext, useContext, useState, useEffect } from "react";
import type { ControlsMap } from "./types";

const EMPTY_CONTROLS: ControlsMap = {};

interface PlaygroundContextType {
  values: Record<string, unknown>;
  setValue: (key: string, value: unknown) => void;
  controls: ControlsMap;
  refresh: { key: number; rotation: number };
  handleRefresh: () => void;
  direction: "ltr" | "rtl";
  setDirection: (direction: "ltr" | "rtl") => void;
  handleDirection: () => void;
}

const PlaygroundContext = createContext<PlaygroundContextType | undefined>(
  undefined,
);

export function usePlayground() {
  const context = useContext(PlaygroundContext);
  if (!context) {
    throw new Error("usePlayground must be used within a PlaygroundProvider");
  }
  return context;
}

interface PlaygroundProviderProps {
  children: React.ReactNode;
  controls?: ControlsMap;
}

export function PlaygroundProvider({
  children,
  controls = EMPTY_CONTROLS,
}: PlaygroundProviderProps) {
  const [values, setValues] = useState<Record<string, unknown>>({});
  const [direction, setDirection] = useState<"ltr" | "rtl">("ltr");
  const [refresh, setRefresh] = useState<{ key: number; rotation: number }>({
    key: 0,
    rotation: 0,
  });

  useEffect(() => {
    const defaults: Record<string, unknown> = {};
    Object.entries(controls).forEach(([key, schema]) => {
      defaults[key] = schema.defaultValue;
    });
    setValues(defaults);
  }, [controls]);

  const setValue = (key: string, value: unknown) => {
    setValues((prev) => ({ ...prev, [key]: value }));
  };

  const handleRefresh = () => {
    setRefresh((prev) => ({
      key: prev.key + 1,
      rotation: prev.rotation + 360,
    }));

    const defaults: Record<string, unknown> = {};
    Object.entries(controls).forEach(([key, schema]) => {
      defaults[key] = schema.defaultValue;
    });
    setValues(defaults);
  };

  const handleDirection = () =>
    setDirection((prev) => (prev === "ltr" ? "rtl" : "ltr"));

  return (
    <PlaygroundContext.Provider
      value={{
        values,
        setValue,
        controls,
        refresh,
        handleRefresh,
        direction,
        setDirection,
        handleDirection,
      }}
    >
      {children}
    </PlaygroundContext.Provider>
  );
}

import type { ControlsMap, PlaygroundValue } from "./types";

type GeneratedResult = {
  imports: Set<string>;
  props: string[];
  children: string | null;
  handlers: string[];
};

function format(code: string) {
  return code
    .replace(/\r\n/g, "\n")
    .replace(/[ \t]+$/gm, "")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function extractImports(code: string) {
  const importRegex = /import\s*\{([\s\S]*?)\}\s*from\s*["'][^"']+["'];/g;

  return (
    code.match(importRegex)?.map((importBlock) => {
      return importBlock.replace(/\{([\s\S]*?)\}/, (match, content) => {
        const items = content
          .split(",")
          .map((i: string) => i.trim())
          .filter((i: string) => i && !i.startsWith("type "));

        const isMultiline = match.includes("\n");

        if (!items.length) return "{}";

        if (!isMultiline) {
          return `{ ${items.join(", ")} }`;
        }

        return `{\n  ${items.join(",\n  ")},\n}`;
      });
    }) ?? []
  );
}

function extractJSXTag(code: string) {
  const m = code.match(/return\s*(?:\(\s*)?(?:<>\s*)?<([A-Z]\w+)/);
  return m?.[1] ?? "";
}

function extractJSXComponentsFromString(input: string) {
  const matches = input.match(/<([A-Z]\w+)/g);
  return new Set(matches?.map((m) => m.slice(1)) ?? []);
}

function extractHandlers(code: string) {
  const matches = code.match(/\s(on[A-Z]\w+)=\{\(\)\s*=>\s*([\s\S]*?)\}/g);
  return matches ?? [];
}

function extractChildren(code: string) {
  const tag = extractJSXTag(code);
  if (!tag) return "{children}";

  const startTagPrefix = `<${tag}`;
  const startIndex = code.indexOf(startTagPrefix);
  if (startIndex === -1) return "{children}";

  let inQuotes = false;
  let quoteChar = null;
  let bracesDepth = 0;
  let i = startIndex + startTagPrefix.length;

  let openingTagEnd = -1;
  let isSelfClosing = false;

  for (; i < code.length; i++) {
    const char = code[i];
    if (inQuotes) {
      if (char === quoteChar) {
        inQuotes = false;
      }
      continue;
    }

    if (char === '"' || char === "'") {
      inQuotes = true;
      quoteChar = char;
    } else if (char === "{") {
      bracesDepth++;
    } else if (char === "}") {
      bracesDepth--;
    } else if (char === ">" && bracesDepth === 0) {
      openingTagEnd = i;
      if (code[i - 1] === "/") {
        isSelfClosing = true;
      }
      break;
    }
  }

  if (isSelfClosing) return null;
  if (openingTagEnd === -1) return "{children}";

  let depth = 1;
  let closingStart = -1;
  for (i = openingTagEnd + 1; i < code.length; i++) {
    const isClosing = code.startsWith(`</${tag}>`, i);
    const isOpening = code.startsWith(startTagPrefix, i);

    if (isClosing) {
      depth--;
      if (depth === 0) {
        closingStart = i;
        break;
      }
    } else if (isOpening) {
      const nextChar = code[i + startTagPrefix.length];
      if (
        !nextChar ||
        nextChar === " " ||
        nextChar === ">" ||
        nextChar === "/" ||
        nextChar === "\n"
      ) {
        depth++;
      }
    }
  }

  if (closingStart === -1) return "{children}";

  return code.slice(openingTagEnd + 1, closingStart).trim();
}

function extractFunctionSignature(code: string) {
  const match = code.match(/export\s+(?:default\s+)?function\s+[A-Za-z0-9_]+/);
  return match ? match[0] : "export function Component";
}

function buildFromControls(
  values: Record<string, PlaygroundValue>,
  controls: ControlsMap = {},
): GeneratedResult {
  const imports = new Set<string>();
  const props: string[] = [];
  let children: string | null = null;
  let fallbackChildren: string | null = null;

  for (const [key, schema] of Object.entries(controls)) {
    const value = values[key] ?? schema.defaultValue;

    if (key === "children") {
      fallbackChildren = String(value);
      continue;
    }

    if (schema.type === "boolean") {
      const mappingKey = String(value);
      if (schema.mapping?.[mappingKey]) {
        schema.mapping[mappingKey].imports?.forEach((i) => imports.add(i));
        if (schema.mapping[mappingKey].children) {
          children = schema.mapping[mappingKey].children;
        }
      }

      if (value === true) {
        props.push(key);
      } else if (value === false && schema.showDefault === true) {
        props.push(`${key}={false}`);
      }
      continue;
    }

    const shouldRender = schema.showDefault || value !== schema.defaultValue;

    if (shouldRender) {
      if (typeof value === "string") {
        props.push(`${key}="${value}"`);
      } else {
        props.push(`${key}={${value}}`);
      }
    }
  }

  if (!children) {
    children = fallbackChildren ?? "{children}";
  }

  return { imports, props, children, handlers: [] };
}

function buildComponent(
  tag: string,
  props: string[],
  handlers: string[],
  children: string | null,
  values: Record<string, PlaygroundValue>,
  template?: (
    props: string,
    children: string | null,
    values: Record<string, PlaygroundValue>,
  ) => string,
  functionSignature: string = "export function Component",
) {
  const allProps = [...props, ...handlers];
  const propLine = allProps.length ? " " + allProps.join(" ") : "";

  let jsx = "";

  if (template) {
    jsx = template(propLine.trim(), children, values);
  } else if (children === null) {
    jsx = `<${tag}${propLine} />`;
  } else {
    jsx = `<${tag}${propLine}>\n      ${children}\n    </${tag}>`;
  }

  return `
${functionSignature}() {
  return (
    ${jsx}
  );
}
`.trim();
}

export function playgroundParser(
  code: string,
  values: Record<string, PlaygroundValue>,
  controls: ControlsMap = {},
  pathArg?: string,
  template?: (
    props: string,
    children: string | null,
    values: Record<string, PlaygroundValue>,
  ) => string,
) {
  if (!code) return "";

  const hasControls = Object.keys(controls).length > 0;

  if (!hasControls && !template) {
    return format(code);
  }

  const baseImports = extractImports(code);
  const tag = extractJSXTag(code);
  const childrenTemplate = extractChildren(code);
  const handlers = extractHandlers(code);
  const functionSignature = extractFunctionSignature(code);

  const generated = buildFromControls(values, controls);
  generated.handlers = handlers;

  if (generated.children === "{children}") {
    generated.children = childrenTemplate;
  }

  const jsxComponents = new Set<string>([
    tag,
    ...extractJSXComponentsFromString(generated.children ?? ""),
  ]);

  const usedImports = new Set<string>();

  for (const imp of baseImports) {
    for (const comp of jsxComponents) {
      if (imp.includes(comp)) {
        usedImports.add(imp);
        break;
      }
    }
  }

  if (pathArg && tag && !Array.from(usedImports).some((i) => i.includes(tag))) {
    if (!pathArg.includes(".demo")) {
      const importPath = `@/${pathArg}`;
      const isDefault = /export\s+default\s+/.test(code);
      if (isDefault) {
        usedImports.add(`import ${tag} from "${importPath}";`);
      } else {
        usedImports.add(`import { ${tag} } from "${importPath}";`);
      }
    }
  }

  generated.imports.forEach((i) => usedImports.add(i));

  const output = `
${Array.from(usedImports).join("\n")}

${buildComponent(tag, generated.props, generated.handlers, generated.children, values, template, functionSignature)}
`;

  return format(output);
}

"use client";

import React, { useMemo } from "react";
import { runtimeRegistry } from "@/generated/runtime-registry";
import { PlaygroundProvider, usePlayground } from "./playground-context";
import { Controls } from "./controls";
import { CodeBlock } from "@/components/docs/code-block";
import { PreviewContainer } from "@/components/docs/preview-container";
import { Skeleton, SkeletonText } from "@/components/ui/core/skeleton";
import { Button, ButtonGroup } from "@/components/ui/core/button";
import { LayoutPanelLeft, RefreshCw, Check, Copy } from "lucide-react";
import { cn } from "@/lib/utils";
import { useComponentSource } from "@/hooks/use-component-source";
import { playgroundParser } from "./playground-parser";
import { useCopyToClipboard } from "@/hooks/use-copy-to-clipboard";
import { useIsMobile } from "@/hooks/use-mobile";
import {
  Tabs,
  TabList,
  TabTrigger,
  TabContent,
} from "@/components/ui/core/tabs";
import type { ControlsMap, PlaygroundProps } from "./types";

function Toolbar() {
  const { direction, refresh, handleRefresh, handleDirection } =
    usePlayground();

  return (
    <ButtonGroup>
      <Button
        tone="outline"
        className="bg-secondary/20 border-2"
        iconOnly
        onClick={handleDirection}
      >
        <LayoutPanelLeft
          className={cn(
            "size-4 text-foreground/60 transition-transform",
            direction === "rtl" && "rotate-180",
          )}
        />
      </Button>
      <Button
        onClick={handleRefresh}
        tone="outline"
        className="bg-secondary/20 border-2"
        iconOnly
      >
        <RefreshCw
          className="size-4 text-foreground/60 transition-transform duration-500"
          style={{ transform: `rotate(${refresh.rotation}deg)` }}
        />
      </Button>
    </ButtonGroup>
  );
}

function CodePanel({ code }: { code: string }) {
  const { isCopied, copyToClipboard } = useCopyToClipboard();

  return (
    <>
      <div className="flex flex-wrap items-center justify-between px-4 py-3 border-b border-border bg-muted/50 gap-2">
        <span className="text-xs font-mono text-muted-foreground">Usage</span>
        <Button
          tone="outline"
          size="sm"
          className="text-[10px] uppercase tracking-wide font-medium text-primary gap-1.5"
          onClick={() => copyToClipboard(code)}
        >
          {isCopied ? (
            <Check className="size-3" />
          ) : (
            <Copy className="size-3" />
          )}
          {isCopied ? "Copied" : "Copy"}
        </Button>
      </div>

      <div className="bg-card/80 p-1 w-full overflow-hidden">
        <CodeBlock
          lang="tsx"
          code={code}
          className="bg-transparent border-none shadow-none rounded-none"
          codeblock={{ allowCopy: false }}
        />
      </div>
    </>
  );
}

function PlaygroundSkeleton({
  hasControls,
  isMobile,
}: {
  hasControls: boolean;
  isMobile: boolean;
}) {
  const codeSection = (
    <div className="border-t border-border">
      <div className="flex flex-wrap items-center justify-between px-4 py-3 border-b border-border bg-muted/50 gap-2">
        <Skeleton className="h-4 w-12" />
        <Skeleton className="h-6 w-16" />
      </div>
      <div className="p-4 bg-card/80">
        <SkeletonText lines={4} />
      </div>
    </div>
  );

  if (isMobile) {
    return (
      <div className="bg-card rounded-2xl border border-border overflow-hidden flex flex-col w-full">
        <div className="flex items-center justify-end gap-2 p-3 border-b border-border">
          <Skeleton className="h-8 w-16" />
        </div>

        <div className="h-[350px] flex items-center justify-center p-8 border-b border-border">
          <Skeleton className="h-8 w-32" />
        </div>

        {hasControls && (
          <div className="p-4 bg-card/50 border-b border-border">
            <Skeleton className="h-4 w-32 mb-4" />
            <SkeletonText lines={3} />
          </div>
        )}

        {codeSection}
      </div>
    );
  }

  return (
    <div className="bg-card rounded-2xl border border-border overflow-hidden w-full">
      <div className="flex items-center justify-end gap-2 p-3 border-b border-border">
        <Skeleton className="h-8 w-16" />
      </div>

      <div
        className={cn(
          "grid min-h-[480px]",
          hasControls ? "grid-cols-12" : "grid-cols-1",
        )}
      >
        {hasControls && (
          <div className="col-span-3 p-6 bg-card border-r border-border">
            <Skeleton className="h-4 w-32 mb-4" />
            <SkeletonText lines={5} />
          </div>
        )}

        <div
          className={cn(
            "flex items-center justify-center p-8",
            hasControls ? "col-span-9" : "col-span-1",
          )}
        >
          <Skeleton className="h-8 w-32" />
        </div>
      </div>

      {codeSection}
    </div>
  );
}

interface PlaygroundContentProps extends PlaygroundProps {
  resolvedPath: string;
}

interface PlaygroundContentProps extends PlaygroundProps {
  resolvedPath: string;
  hideToolbar?: boolean;
}

function PlaygroundContent({
  resolvedPath,
  Component: ComponentProp,
  controls: controlsProp,
  template,
  orientation: orientationProp,
  hideToolbar,
}: PlaygroundContentProps) {
  const {
    values,
    direction,
    refresh,
    controls: contextControls,
  } = usePlayground();
  const { code: sourceCode, loading } = useComponentSource(resolvedPath);
  const isMobile = useIsMobile();

  const registryEntry =
    runtimeRegistry[resolvedPath as keyof typeof runtimeRegistry];

  const Component = useMemo(() => {
    if (ComponentProp) return ComponentProp;
    if (!registryEntry) return null;
    return (registryEntry as any).Component || (registryEntry as any);
  }, [ComponentProp, registryEntry]);

  const controls = controlsProp || contextControls;

  const orientation = orientationProp || (isMobile ? "vertical" : "horizontal");

  const code = useMemo(
    () =>
      playgroundParser(
        sourceCode || "",
        values as Record<string, string | number | boolean>,
        controls,
        resolvedPath,
        template,
      ),
    [sourceCode, values, controls, resolvedPath, template],
  );

  const hasControls = Boolean(controls && Object.keys(controls).length > 0);

  if (loading) {
    return <PlaygroundSkeleton hasControls={hasControls} isMobile={isMobile} />;
  }

  const previewArea = Component ? (
    <div className="relative h-full overflow-visible">
      <div className="absolute inset-0 bg-dots pointer-events-none" />
      <div className="absolute inset-x-0 bottom-0 h-1/4 bg-linear-to-t from-card/80 via-card/40 to-transparent pointer-events-none" />

      <PreviewContainer className="relative flex h-full items-center justify-center">
        <React.Suspense
          fallback={
            <div className="flex w-full items-center justify-center p-8">
              <Skeleton className="h-6 w-24" />
            </div>
          }
        >
          <Component {...values} />
        </React.Suspense>
      </PreviewContainer>
    </div>
  ) : null;

  if (orientation === "vertical" || !Component) {
    return (
      <div className="bg-card rounded-2xl border border-border overflow-hidden flex flex-col w-full">
        <div key={refresh.key} dir={direction} className="flex flex-col w-full">
          {!hideToolbar && (
            <div className="flex items-center justify-end gap-2 p-3 border-b border-border">
              <Toolbar />
            </div>
          )}

          {Component && (
            <div className="h-[350px] relative border-b border-border overflow-visible">
              {previewArea}
            </div>
          )}

          {hasControls && (
            <div className="p-4 bg-card/50 border-b border-border">
              <div className="text-xs font-mono text-muted-foreground uppercase tracking-wider mb-4">
                Component Configuration
              </div>
              <Controls />
            </div>
          )}
        </div>

        <div className="border-t border-border">
          <CodePanel code={code} />
        </div>
      </div>
    );
  }

  return (
    <div className="bg-card rounded-2xl border border-border overflow-hidden w-full">
      <div key={refresh.key} dir={direction} className="flex flex-col w-full">
        {!hideToolbar && (
          <div className="flex items-center justify-end gap-2 border-b border-border p-3">
            <Toolbar />
          </div>
        )}

        <div
          className={cn(
            "grid min-h-[480px]",
            hasControls ? "grid-cols-12" : "grid-cols-1",
          )}
        >
          {hasControls && (
            <div className="col-span-3 border-r border-border overflow-y-auto p-6 bg-card">
              <div className="text-xs font-mono text-muted-foreground uppercase tracking-wider mb-4">
                Component Configuration
              </div>
              <Controls />
            </div>
          )}

          <div
            className={cn(
              "relative",
              hasControls ? "col-span-9" : "col-span-1",
            )}
          >
            {previewArea}
          </div>
        </div>

        <div className="border-t border-border">
          <CodePanel code={code} />
        </div>
      </div>
    </div>
  );
}

function resolveRegistryKey(comp: string) {
  if (!comp) return "";

  const normalized = comp
    .replace(/\.(tsx|ts|jsx|js)$/, "")
    .replace(/^\/+|\/+$/g, "");

  if (runtimeRegistry[normalized as keyof typeof runtimeRegistry])
    return normalized;

  const keys = Object.keys(runtimeRegistry);
  if (keys.includes(normalized)) return normalized;

  const match = keys.find(
    (key) =>
      key.endsWith(normalized) || key.endsWith(normalized.replace(".demo", "")),
  );
  return match || normalized;
}

export function Playground(props: PlaygroundProps) {
  const { path, controls: controlsProp } = props;
  const [activeTab, setActiveTab] = React.useState<string>(() => {
    if (Array.isArray(path)) return path[0] || "";
    return path || "";
  });
  const [autoControls, setAutoControls] = React.useState<
    ControlsMap | undefined
  >(undefined);

  const resolvedPath = useMemo(
    () => resolveRegistryKey(activeTab),
    [activeTab],
  );

  React.useEffect(() => {
    if (controlsProp) {
      setAutoControls(undefined);
      return;
    }

    const registryEntry =
      runtimeRegistry[resolvedPath as keyof typeof runtimeRegistry];

    if (registryEntry && (registryEntry as any).module) {
      (registryEntry as any).module().then((mod: any) => {
        setAutoControls(mod.controls || {});
      });
    } else {
      setAutoControls({});
    }
  }, [resolvedPath, controlsProp]);

  const controls = controlsProp || autoControls || {};

  if (Array.isArray(path)) {
    return (
      <PlaygroundProvider controls={controls}>
        <Tabs
          selectedKey={activeTab}
          onSelectionChange={(key) => setActiveTab(key as string)}
          width="full"
          className="bg-card rounded-2xl border border-border overflow-hidden w-full flex flex-col"
        >
          <div className="flex items-center justify-between border-b border-border p-1 px-3 min-h-[57px]">
            <TabList
              className="border-none bg-transparent p-0 gap-1 h-auto"
              tone="ghost"
              size="sm"
            >
              {path.map((p) => {
                const name = p.split("/").pop() || p;
                return (
                  <TabTrigger
                    key={p}
                    id={p}
                    className="selected:bg-muted selected:text-foreground text-muted-foreground px-3 py-1.5 h-8 text-xs font-medium rounded-lg"
                  >
                    {name}
                  </TabTrigger>
                );
              })}
            </TabList>
            <div className="flex items-center gap-2">
              <Toolbar />
            </div>
          </div>
          {path.map((p) => {
            const resolved = resolveRegistryKey(p);
            return (
              <TabContent
                key={p}
                id={p}
                className="p-0 border-none outline-none"
              >
                <PlaygroundContent
                  {...props}
                  path={p}
                  resolvedPath={resolved}
                  hideToolbar
                />
              </TabContent>
            );
          })}
        </Tabs>
      </PlaygroundProvider>
    );
  }

  return (
    <PlaygroundProvider controls={controls}>
      <PlaygroundContent {...props} resolvedPath={resolvedPath} />
    </PlaygroundProvider>
  );
}

export type ControlType =
  | "select"
  | "toggle-group"
  | "boolean"
  | "text"
  | "textarea"
  | "number";

export type PlaygroundValue = string | number | boolean;

export interface ControlOption {
  value: string | number;
  label: string;
}

export interface CodeGenOutput {
  imports?: string[];
  children?: string;
}

export interface ControlSchema {
  type: ControlType;
  defaultValue: PlaygroundValue;
  label?: string;
  options?: ControlOption[];
  placeholder?: string;
  min?: number;
  max?: number;
  showDefault?: boolean;
  mapping?: Record<string, CodeGenOutput>;
}

export type ControlsMap = Record<string, ControlSchema>;

export interface DemoComponent<T> extends React.FC<T> {
  controls?: ControlsMap;
  template?: (props: string, children: string | null) => string;
}

export interface PlaygroundProps {
  path?: string | string[];
  Component?: React.ComponentType<any>;
  orientation?: "horizontal" | "vertical";
  controls?: ControlsMap;
  template?: (props: string, children: string | null) => string;
}

