"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "motion/react";
import {
  AnimatedToggleGroup,
  AnimatedToggleItem,
} from "@/components/ui/motion/animated-toggle-group";
import { Check, Clipboard } from "lucide-react";
import { useCopyToClipboard } from "@/hooks/use-copy-to-clipboard";
import { cn } from "@/lib/utils";

type PackageManager = "npm" | "pnpm" | "yarn" | "bun";
const PACKAGE_MANAGER_LABELS: Record<PackageManager, string> = {
  npm: "npm",
  pnpm: "pnpm",
  yarn: "yarn",
  bun: "bun",
};

type PackageInstallProps = {
  packageName?: string;
  command?: "install" | "add";
  title?: string;
  className?: string;
};

export function PackageInstall({
  packageName,
  command = "install",
  title,
  className,
}: PackageInstallProps) {
  const [manager, setManager] = useState<PackageManager>("npm");
  const { isCopied, copyToClipboard } = useCopyToClipboard();

  const cliCommands: Record<PackageManager, string> =
    command === "add"
      ? {
          npm: `npx libravelui@latest add ${packageName}`,
          pnpm: `pnpm dlx libravelui@latest add ${packageName}`,
          yarn: `yarn dlx libravelui@latest add ${packageName}`,
          bun: `bunx libravelui@latest add ${packageName}`,
        }
      : {
          npm: `npm install ${packageName}`,
          pnpm: `pnpm add ${packageName}`,
          yarn: `yarn add ${packageName}`,
          bun: `bun add ${packageName}`,
        };

  const handleCopy = () => {
    copyToClipboard(cliCommands[manager]);
  };

  return (
    <div className={cn("flex flex-col gap-2", className)}>
      <div className="flex flex-col sm:flex-row sm:items-center justify-between sm:gap-3 w-full">
        {title && <span className="text-sm font-medium">{title}</span>}
        <div className="overflow-x-auto [scrollbar-width:none]">
          <AnimatedToggleGroup
            value={manager}
            onValueChange={(val) => setManager(val as PackageManager)}
          >
            {(Object.keys(PACKAGE_MANAGER_LABELS) as PackageManager[]).map(
              (key) => (
                <AnimatedToggleItem
                  key={key}
                  value={key}
                  className="text-xs sm:text-sm size-fit py-0.5 px-1.5 sm:px-2"
                >
                  {PACKAGE_MANAGER_LABELS[key]}
                </AnimatedToggleItem>
              ),
            )}
          </AnimatedToggleGroup>
        </div>
      </div>

      <div className="relative w-full overflow-hidden rounded-lg border border-border/80 bg-[radial-gradient(circle_at_0_0,--theme(--color-primary/8%),transparent_55%),radial-gradient(circle_at_100%_100%,--theme(--color-accent/10%),transparent_55%)]">
        {/* Copy Button */}
        <button
          onClick={handleCopy}
          className="absolute right-2 top-1/2 -translate-y-1/2 z-10 rounded-sm bg-primary/5 p-0.5 text-xs border border-border/60 text-foreground/70 hover:text-foreground transition [&>svg]:size-4"
        >
          {isCopied ? <Check /> : <Clipboard />}
        </button>

        <AnimatePresence mode="wait" initial={false}>
          <motion.pre
            key={manager}
            initial={{ opacity: 0, y: 4 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -4 }}
            transition={{ duration: 0.2, ease: "easeOut" }}
            className="flex items-center gap-2 bg-linear-to-tr from-background/95 via-background/80 to-background/60 px-3 pr-10 py-2.5 text-xs font-mono text-foreground/90 [scrollbar-width:none]"
          >
            <span className="select-none text-muted-foreground/80 shrink-0">
              $
            </span>
            <code className="min-w-0 overflow-x-auto scrollbar-hidden whitespace-nowrap">
              {cliCommands[manager]}
            </code>
          </motion.pre>
        </AnimatePresence>
      </div>
    </div>
  );
}

"use client";

import React, { useState, useMemo } from "react";
import Link from "next/link";
import { Button } from "@/components/ui/core/button";
import { RefreshCw } from "lucide-react";
import { cn } from "@/lib/utils";
import { Loader } from "@/components/ui/core/loader";
import { runtimeRegistry } from "@/generated/runtime-registry";

interface PreviewBlockItem {
  path: string;
  title?: string;
  href?: string;
  className?: string | string[];
}

interface ClassNames {
  grid?: string | string[];
  wrapper?: string | string[];
  comp?: string | string[];
}

interface PreviewBlockProps {
  path: string | PreviewBlockItem | (string | PreviewBlockItem)[];
  cols?: number;
  classNames?: ClassNames;
}

interface PreviewItemProps {
  path: string;
  title?: string;
  href?: string;
  className?: string | string[];
  wrapperClass?: string | string[];
}

function PreviewItem({
  path: rawPath,
  title,
  href,
  className,
  wrapperClass,
}: PreviewItemProps) {
  const [refresh, setRefresh] = useState<{
    key: number;
    rotation: number;
  }>({
    key: 0,
    rotation: 0,
  });

  const path = useMemo(() => {
    return rawPath.replace(/\.(tsx|ts|jsx|js)$/, "").replace(/^\/+|\/+$/g, "");
  }, [rawPath]);

  const handleRefresh = () => {
    setRefresh((prev) => ({
      ...prev,
      key: prev.key + 1,
      rotation: prev.rotation + 360,
    }));
  };

  const registryEntry = runtimeRegistry[path as keyof typeof runtimeRegistry];
  const Demo = useMemo(() => {
    if (!registryEntry) {
      return () => (
        <div className="text-xs text-destructive p-4">Not found: {path}</div>
      );
    }
    return (registryEntry as any).Component || (registryEntry as any);
  }, [registryEntry, path]);

  const displayName = useMemo(() => {
    if (title) return title;
    if ((registryEntry as any)?.name) return (registryEntry as any).name;
    const name = path.split("/").pop() || path;
    return name
      .split("-")
      .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
      .join(" ");
  }, [path, title, registryEntry]);

  const finalHref = useMemo(() => {
    if (href) return href;
    if ((registryEntry as any)?.url) return (registryEntry as any).url;
    return `/docs/${path}`;
  }, [path, href, registryEntry]);

  return (
    <div
      className={cn(
        "relative border flex flex-col items-center justify-center w-full sm:max-w-sm min-h-48 rounded-xl overflow-hidden not-prose bg-card",
        wrapperClass,
      )}
    >
      <Button
        onClick={handleRefresh}
        tone="secondary"
        size="xs"
        iconOnly
        aria-label="Refresh preview"
        className="absolute inset-e-2 top-2 z-10"
      >
        <RefreshCw
          className="transition-transform duration-300 size-3"
          style={{ transform: `rotate(${refresh.rotation}deg)` }}
        />
      </Button>

      <div
        key={refresh.key}
        className={cn(
          "flex flex-col items-center justify-center w-full h-full p-6 not-prose",
          className,
        )}
      >
        <React.Suspense fallback={<Loader />}>
          <Demo />
        </React.Suspense>
      </div>

      <Link
        href={finalHref}
        className="w-full p-2 border-t font-mono text-[10px] text-center truncate hover:bg-accent transition-colors ease-linear text-muted-foreground"
      >
        {displayName}
      </Link>
    </div>
  );
}

export function PreviewBlock({
  path: pathProp,
  cols = 3,
  classNames,
}: PreviewBlockProps) {
  const gridColsClass =
    {
      1: "grid-cols-1",
      2: "grid-cols-1 sm:grid-cols-2",
      3: "grid-cols-1 sm:grid-cols-2 md:grid-cols-3",
      4: "grid-cols-1 sm:grid-cols-2 md:grid-cols-4",
      5: "grid-cols-1 sm:grid-cols-2 md:grid-cols-5",
    }[cols] || "grid-cols-1 sm:grid-cols-2 md:grid-cols-3";

  const items = Array.isArray(pathProp) ? pathProp : [pathProp];

  return (
    <div className={cn("grid gap-4", gridColsClass, classNames?.grid)}>
      {items.map((item, idx) => {
        const path = typeof item === "string" ? item : item.path;
        const title = typeof item === "string" ? undefined : item.title;
        const href = typeof item === "string" ? undefined : item.href;
        const className =
          typeof item === "string"
            ? classNames?.comp
            : item.className || classNames?.comp;

        return (
          <PreviewItem
            key={`${path}-${idx}`}
            path={path}
            title={title}
            href={href}
            className={className}
            wrapperClass={classNames?.wrapper}
          />
        );
      })}
    </div>
  );
}

