import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/core/dialog";

type MovieFormData = {
  title: string;
  slug: string;
  overview: string;
  poster_path: string;
  backdrop_path: string;
  release_date: CalendarDate | null;
  language: string;
  genres: (string | number)[];
};

function getValue(
  e: string | ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
) {
  return typeof e === "string" ? e : e.target.value;
}

function slugify(value: string) {
  return value
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/(^-|-$)+/g, "");
}

export default function GridForm() {
  const [open, setOpen] = useState(false);
  const [formData, setFormData] = useState<MovieFormData>({
    title: "The Boys",
    slug: "",
    overview:
      "A group of vigilantes known informally as “The Boys” set out to take down corrupt superheroes with no more than blue-collar grit and a willingness to fight dirty.",
    poster_path:
      "https://image.tmdb.org/t/p/w1280/2zmTngn1tYC1AvfnrFLhxeD82hz.jpg",
    backdrop_path:
      "https://image.tmdb.org/t/p/original/b4NSwuakKuasGl6C16JqI4jZgZd.jpg",
    release_date: new CalendarDate(2019, 6, 26),
    language: "en",
    genres: [
      "action",
      "drama",
      "thriller",
      "science-fiction",
      "satire",
      "superhero",
    ],
  });

  useEffect(() => {
    if (formData.title.trim().length > 0) {
      setFormData((prev) => ({
        ...prev,
        slug: slugify(prev.title),
      }));
    } else {
      setFormData((prev) => ({ ...prev, slug: "" }));
    }
  }, [formData.title]);

  const handleChange = <K extends keyof MovieFormData>(
    field: K,
    value: MovieFormData[K]
  ) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const handleSubmit = (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setOpen(true);
  };

  return (
    <div className="grid gap-4 w-full max-w-lg">
      <Heading>Add Movie</Heading>

      <Form onSubmit={handleSubmit} className="grid gap-4">
        <div className="flex items-start gap-2">
          <TextField>
            <Label>Movie Title</Label>
            <Input
              placeholder="Movie title"
              value={formData.title}
              onChange={(e) => handleChange("title", getValue(e))}
            />
          </TextField>

          <TextField>
            <Label>Slug</Label>
            <Input
              placeholder="movie-slug"
              value={formData.slug}
              readOnly
              disabled
            />
          </TextField>
        </div>

        <TextField
          value={formData.overview}
          onChange={(e) => handleChange("overview", getValue(e as string))}
        >
          <Label>Overview</Label>
          <Textarea placeholder="Movie overview" />
        </TextField>

        <div className="flex items-start gap-2">
          <TextField>
            <Label>Poster Path</Label>
            <Input
              placeholder="/poster.jpg"
              value={formData.poster_path}
              onChange={(e) => handleChange("poster_path", getValue(e))}
            />
          </TextField>

          <TextField>
            <Label>Backdrop Path</Label>
            <Input
              placeholder="/backdrop.jpg"
              value={formData.backdrop_path}
              onChange={(e) => handleChange("backdrop_path", getValue(e))}
            />
          </TextField>
        </div>

        <div className="flex items-start gap-2">
          <DatePicker
            className="w-full"
            value={formData.release_date}
            onChange={(date) => handleChange("release_date", date)}
          >
            <Label>Release Date</Label>
            <DatePickerTrigger />
          </DatePicker>

          <div className="flex-1 grid gap-1">
            <Label>Language</Label>
            <Select
              placeholder="English"
              items={[
                { id: "en", label: "English" },
                { id: "fr", label: "French" },
                { id: "es", label: "Spanish" },
              ]}
              selectedKey={formData.language}
              onSelectionChange={(value) =>
                handleChange("language", value as string)
              }
              classNames={{ trigger: "min-w-48" }}
            />
          </div>
        </div>

        <div className="grid gap-1">
          <Label>Genres</Label>
          <MultipleSelect
            placeholder="Select genres"
            items={genres}
            value={formData.genres}
            onChange={(values) => handleChange("genres", values)}
          />
        </div>

        <Button type="submit" className="w-fit">
          Preview
        </Button>
      </Form>

      <Dialog isOpen={open} onOpenChange={setOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>Preview Movie Data</DialogTitle>
          </DialogHeader>

          <pre className="bg-muted text-sm p-4 rounded-md overflow-auto max-h-96">
            {JSON.stringify(
              {
                ...formData,
                release_date: formData.release_date
                  ? formData.release_date.toString()
                  : null,
              },
              null,
              2
            )}
          </pre>

          <div className="flex justify-end gap-2 mt-4">
            <Button tone="outline" onClick={() => setOpen(false)}>
              Close
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

