export default function DragAndDrop() {
  const list = useListData({
    initialItems: movies,
  });

  const { dragAndDropHooks } = useDragAndDrop({
    getItems: (keys) =>
      [...keys].map((key) => ({
        "text/plain": list.getItem(key)?.title ?? "",
      })),
    onReorder(e) {
      if (e.target.dropPosition === "before") {
        list.moveBefore(e.target.key, e.keys);
      } else if (e.target.dropPosition === "after") {
        list.moveAfter(e.target.key, e.keys);
      }
    },
  });
  return (
    <div className="rounded-lg border p-4">
      <Table
        allowResize
        aria-label="Movies"
        selectionMode="multiple"
        dragAndDropHooks={dragAndDropHooks}
      >
        <TableHeader>
          <TableColumn className="w-0">#</TableColumn>
          <TableColumn isResizable isRowHeader>
            Title
          </TableColumn>
          <TableColumn isResizable>Director</TableColumn>
          <TableColumn>Genre</TableColumn>
          <TableColumn>Year</TableColumn>
          <TableColumn>Rating</TableColumn>
        </TableHeader>
        <TableBody items={list.items}>
          {(item) => (
            <TableRow>
              <TableCell>{item.id}</TableCell>
              <TableCell>{item.title}</TableCell>
              <TableCell>{item.director}</TableCell>
              <TableCell>{item.genre}</TableCell>
              <TableCell>{item.year}</TableCell>
              <TableCell>
                <div className="flex items-center gap-x-2">
                  <Star className="size-3.5 text-yellow-300 fill-yellow-300" />{" "}
                  <span>{item.rating}</span>
