"use client";

import { useMemo } from "react";
import { ComponentSource } from "@/components/docs/component-source";
import {
  Accordion,
  AccordionItem,
  AccordionTrigger,
  AccordionContent,
} from "@/components/ui/core/accordion";
import { PackageInstall } from "@/components/docs/package-install";
import { CodeBlock } from "@/components/docs/code-block";

export type InstallationProps = {
  path?: string;
  name?: string;
  section?: string;
  packages?: string | string[];
  requiredBlock?: React.ReactNode;
};

export function Installation({
  path: rawPath,
  name: nameProp,
  section: sectionProp,
  packages = ["tailwind-merge", "clsx", "motion"],
  requiredBlock,
}: InstallationProps) {
  const path = useMemo(() => {
    if (rawPath) return rawPath.replace(/^\/+|\/+$/g, "");
    const section = sectionProp || "motion";
    const name = nameProp || "";
    return `components/ui/${section}/${name}`.replace(/^\/+|\/+$/g, "");
  }, [rawPath, nameProp, sectionProp]);

  const name = useMemo(() => {
    if (nameProp) return nameProp;
    return path.split("/").pop() || "";
  }, [path, nameProp]);

  const section = useMemo(() => {
    if (sectionProp) return sectionProp;
    const parts = path.split("/");
    return parts[parts.length - 2] || "motion";
  }, [path, sectionProp]);

  const packageList = Array.isArray(packages)
    ? packages
    : typeof packages === "string"
      ? [packages]
      : [];

  return (
    <div className="flex flex-col gap-4 not-prose">
      {/* CLI quick start */}
      <Accordion tone="outline" size="full" defaultExpandedKeys={["cli"]}>
        <AccordionItem id="cli">
          <AccordionTrigger>
            <h3 className="text-sm font-semibold">Quick start (CLI)</h3>
            <p className="text-xs text-muted-foreground">
              Run a single command to install the component and dependencies.
            </p>
          </AccordionTrigger>
          <AccordionContent className="pt-1">
            <PackageInstall packageName={name} command="add" />
          </AccordionContent>
        </AccordionItem>

        <AccordionItem id="manual">
          <AccordionTrigger>
            <h3 className="text-sm font-semibold text-foreground">
              Manual installation
            </h3>
            <p className="mt-1 text-xs text-muted-foreground">
              Install the dependencies, add the utility helpers, then copy the
              component into your codebase.
            </p>
          </AccordionTrigger>
          <AccordionContent>
            {requiredBlock && <div className="mt-2 mb-6">{requiredBlock}</div>}
            <ol className="flex flex-col gap-4 text-muted-foreground">
              {steps.map((item) => (
                <li key={item.step} className="space-y-2">
