"use client";

import { Sun, Moon } from "lucide-react";
import * as React from "react";
import { useTheme } from "next-themes";
import { Button, type ButtonProps } from "@/components/ui/core/button";

export default function AppearanceButton({ ...props }: ButtonProps) {
  const { theme, setTheme } = useTheme();
  const [mounted, setMounted] = React.useState(false);

  React.useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) {
    return (
      <Button tone="outline" iconOnly {...props}>
        <Sun />
      </Button>
    );
  }

  return (
    <Button
      tone="outline"
      iconOnly
      onClick={() => setTheme(theme === "dark" ? "light" : "dark")}
      {...props}
    >
      {theme === "dark" ? <Sun /> : <Moon />}
    </Button>
  );
}

"use client";

import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/core/dropdown-menu";
import { Monitor, Moon, Sun } from "lucide-react";
import { useTheme } from "next-themes";
import { type HTMLAttributes, useEffect, useState } from "react";
import { cn } from "@/lib/utils";
import type { ButtonProps } from "@/components/ui/core/button";

const themes = [
  { label: "Light", value: "light", icon: Sun },
  { label: "Dark", value: "dark", icon: Moon },
  { label: "System", value: "system", icon: Monitor },
] as const;

export default function AppearanceDropdown({
  className,
  tone = "ghost",
  ...props
}: HTMLAttributes<HTMLDivElement> & {
  tone?: ButtonProps["tone"];
}) {
  const { theme, setTheme } = useTheme();

  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);

  if (!mounted) {
    return (
      <div className={className} {...props}>
        <DropdownMenu>
          <DropdownMenuTrigger tone={tone} iconOnly>
            <Monitor />
          </DropdownMenuTrigger>
        </DropdownMenu>
      </div>
    );
  }

  const currentTheme = themes.find((t) => t.value === theme) ?? themes[2];
  const CurrentIcon = currentTheme.icon;

  return (
    <div className={className} {...props}>
      <DropdownMenu>
        <DropdownMenuTrigger tone={tone} iconOnly>
          <CurrentIcon />
          <span className="sr-only">Toggle theme</span>
        </DropdownMenuTrigger>

        <DropdownMenuContent>
          {themes.map(({ label, value, icon: Icon }) => (
            <DropdownMenuItem
              key={value}
              onClick={() => setTheme(value)}
              className={cn(
                "cursor-pointer",
                theme === value && "font-semibold",
              )}
            >
              <Icon data-slot="indicator" />
              <span className="ms-2">{label}</span>
            </DropdownMenuItem>
          ))}
        </DropdownMenuContent>
      </DropdownMenu>
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";
import { Check } from "lucide-react";
import { useTheme } from "next-themes";
import { motion, AnimatePresence, LayoutGroup } from "motion/react";
import { useId } from "react";

type ThemeValue = "light" | "dark" | "system";

type AppearanceTheme = {
  value: ThemeValue;
  label?: string;
  src?: string;
};

type AppearanceImageProps = {
  themes?: AppearanceTheme[];
  images?: Partial<Record<ThemeValue, string>>;
};

export default function AppearanceImage({
  themes,
  images,
}: AppearanceImageProps) {
  const id = useId();
  const { theme, setTheme } = useTheme();

  const defaultThemes: AppearanceTheme[] = [
    {
      value: "light",
      label: "Light",
      src: "/assets/appearance/light-theme.png",
    },
    {
      value: "system",
      label: "System",
      src: "/assets/appearance/system-theme.png",
    },
    {
      value: "dark",
      label: "Dark",
      src: "/assets/appearance/dark-theme.png",
    },
  ];

  const finalThemes: AppearanceTheme[] =
    themes ??
    defaultThemes.map((theme) => ({
      ...theme,
      src: images?.[theme.value] ?? theme.src,
    }));

  return (
    <LayoutGroup id={id}>
      <div className="flex gap-4">
        {finalThemes.map(({ value, src, label }) => (
          <div
            key={value}
            onClick={() => setTheme(value)}
            className="group flex flex-col items-center gap-4 cursor-pointer"
          >
            <div className="relative flex justify-center">
              <motion.img
                src={src || ""}
                alt={value}
                className={cn(
                  "max-w-52 rounded-lg transition ease-in-out hover:opacity-100",
                  theme === value ? "opacity-100" : "opacity-70",
                )}
              />
              <AnimatePresence>
                {theme === value && (
                  <motion.div
                    layoutId="theme-border"
                    className="absolute inset-0 rounded-lg border-3 border-primary"
                    transition={{ type: "spring", stiffness: 400, damping: 30 }}
                  />
                )}
              </AnimatePresence>
              {theme === value && (
                <motion.div
                  initial={{ scale: 0, opacity: 0 }}
                  animate={{ scale: 1, opacity: 1 }}
                  exit={{ scale: 0, opacity: 0 }}
                  className="bg-primary text-background absolute bottom-2 inline-flex [&_svg]:size-3.5 items-center justify-center rounded-full p-0.5 font-bold"
                >
                  <Check />
                </motion.div>
              )}
            </div>
            <div className="relative flex items-center justify-center">
              {theme === value && (
                <motion.div
                  layoutId="theme-label-bg"
                  className="absolute rounded-lg bg-primary w-full h-full"
                  transition={{
                    type: "spring",
                    stiffness: 400,
                    damping: 30,
                    delay: 0.05,
                  }}
                />
              )}
              <span
                className={cn(
                  "relative z-10 px-4 py-1 capitalize rounded-lg transition-all",
                  theme === value
                    ? "text-primary-foreground"
                    : "text-muted-foreground group-hover:bg-primary group-hover:text-primary-foreground",
                )}
              >
                {label || value}
              </span>
            </div>
          </div>
        ))}
      </div>
    </LayoutGroup>
  );
}

"use client";

import { cn } from "@/lib/utils";
import { SunMoon, Moon, Sun } from "lucide-react";
import { useTheme } from "next-themes";
import { motion, LayoutGroup } from "motion/react";
import { type HTMLAttributes } from "react";

export default function AppearanceTab({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  const { theme, setTheme } = useTheme();

  const tabs: {
    value: "light" | "dark" | "system";
    icon: React.ReactNode;
    label: string;
  }[] = [
    { value: "light", icon: <Sun />, label: "Light" },
    { value: "dark", icon: <Moon />, label: "Dark" },
    { value: "system", icon: <SunMoon />, label: "System" },
  ];

  return (
    <LayoutGroup>
      <div
        className={cn(
          "inline-flex gap-1 rounded-xl bg-secondary p-1 w-fit relative",
          className,
        )}
        {...props}
      >
        {tabs.map(({ value, icon, label }) => {
          const active = theme === value;
          return (
            <button
              key={value}
              onClick={() => setTheme(value)}
              className={cn(
                "relative flex items-center rounded-lg px-3.5 py-1.5 transition-colors cursor-pointer [&_svg:not([class*='size-'])]:size-4",
                active
                  ? "text-primary-foreground"
                  : "text-foreground/70 hover:text-foreground",
              )}
            >
              {active && (
                <motion.div
                  layoutId="appearance-tab-bg"
                  className="absolute inset-0 bg-primary rounded-lg shadow-xs"
                  transition={{ type: "spring", stiffness: 400, damping: 30 }}
                />
              )}
              <span className="relative flex items-center">
                {icon}
                <span className="ml-1.5 text-sm">{label}</span>
              </span>
            </button>
          );
        })}
      </div>
    </LayoutGroup>
  );
}

import * as React from "react";

export interface ThemeProviderProps {
  themes?: string[];
  forcedTheme?: string;
  enableSystem?: boolean;
  disableTransitionOnChange?: boolean;
  enableColorScheme?: boolean;
  storageKey?: string;
  defaultTheme?: string;
  attribute?: string | "class";
  value?: { [themeName: string]: string };
  nonce?: string;
  children?: React.ReactNode;
}

export type Appearance = "light" | "dark" | "system";

interface UseThemeProps {
  setTheme: (theme: string) => void;
  theme?: string;
  resolvedTheme?: string;
  systemTheme?: "light" | "dark";
  themes: string[];
}

const ThemeContext = React.createContext<UseThemeProps | undefined>(undefined);
const defaultThemes = ["light", "dark"];

export const useTheme = () => {
  const context = React.useContext(ThemeContext);
  if (!context) {
    throw new Error("useTheme must be used within a ThemeProvider");
  }
  return context;
};

export const ThemeProvider = (props: ThemeProviderProps) => {
  const context = React.useContext(ThemeContext);

  if (context) return <React.Fragment>{props.children}</React.Fragment>;
  return <Theme {...props} />;
};

const Theme = ({
  forcedTheme,
  disableTransitionOnChange = false,
  enableSystem = true,
  enableColorScheme = true,
  storageKey = "theme",
  themes = defaultThemes,
  defaultTheme = "system",
  attribute = "class",
  value,
  children,
  nonce,
}: ThemeProviderProps) => {
  const [theme, setThemeState] = React.useState(() =>
    getTheme(storageKey, defaultTheme),
  );
  const [resolvedTheme, setResolvedTheme] = React.useState(() =>
    getTheme(storageKey),
  );
  const [mounted, setMounted] = React.useState(false);

  const applyTheme = React.useCallback(
    (theme: string) => {
      let resolved = theme;
      if (!resolved) return;

      if (theme === "system" && enableSystem) {
        resolved = getSystemTheme();
      }

      const name = value ? value[resolved] : resolved;
      const d = document.documentElement;

      if (attribute === "class") {
        d.classList.remove(...(value ? Object.values(value) : themes!));
        if (name) d.classList.add(name);
      } else {
        if (name) {
          d.setAttribute(attribute, name);
        } else {
          d.removeAttribute(attribute);
        }
      }

      if (enableColorScheme) {
        const fallback = defaultThemes.includes(resolved) ? resolved : null;
        const colorScheme = forcedTheme ? forcedTheme : fallback;

        if (colorScheme) {
          d.style.colorScheme = colorScheme;
        }
      }
    },
    [attribute, enableColorScheme, forcedTheme, themes, value, enableSystem],
  );

  const disableTransitions = React.useCallback(() => {
    const css = document.createElement("style");
    css.append(
      document.createTextNode(
        `*,*::before,*::after{-webkit-transition:none!important;-moz-transition:none!important;-o-transition:none!important;-ms-transition:none!important;transition:none!important}`,
      ),
    );
    document.head.append(css);

    return () => {
      (() => window.getComputedStyle(document.body))();

      requestAnimationFrame(() => {
        css.remove();
      });
    };
  }, []);

  const setTheme = React.useCallback(
    (value: string) => {
      const cleanup = disableTransitionOnChange ? disableTransitions() : null;

      setThemeState(value);

      try {
        localStorage.setItem(storageKey, value);
      } catch (e) {}

      if (cleanup) cleanup();
    },
    [storageKey, disableTransitionOnChange, disableTransitions],
  );

  const handleMediaQuery = React.useCallback(
    (e: MediaQueryListEvent | MediaQueryList) => {
      const resolved = getSystemTheme(e);
      setResolvedTheme(resolved);

      if (theme === "system" && enableSystem && !forcedTheme) {
        applyTheme("system");
      }
    },
    [theme, enableSystem, forcedTheme],
  );

  React.useEffect(() => {
    const media = window.matchMedia("(prefers-color-scheme: dark)");
    media.addEventListener("change", handleMediaQuery);
    handleMediaQuery(media);

    return () => media.removeEventListener("change", handleMediaQuery);
  }, [handleMediaQuery]);

  React.useEffect(() => {
    const handleStorage = (e: StorageEvent) => {
      if (e.key !== storageKey) {
        return;
      }

      const theme = e.newValue || defaultTheme;
      setTheme(theme!);
    };

    window.addEventListener("storage", handleStorage);
    return () => window.removeEventListener("storage", handleStorage);
  }, [setTheme, storageKey, defaultTheme]);

  React.useEffect(() => {
    const d = document.documentElement;
    if (attribute === "class") {
      d.classList.remove(...themes);
    } else {
      d.removeAttribute(attribute);
    }
    d.setAttribute("style", "");
    if (forcedTheme) {
      applyTheme(forcedTheme);
    } else {
      applyTheme(theme);
    }
  }, [forcedTheme, theme]);

  React.useEffect(() => {
    setMounted(true);
  }, []);

  const providerValue = React.useMemo(
    () => ({
      theme,
      setTheme,
      forcedTheme,
      resolvedTheme: theme === "system" ? resolvedTheme : theme,
      systemTheme: (enableSystem ? resolvedTheme : undefined) as
        | "light"
        | "dark"
        | undefined,
      themes: themes || [],
    }),
    [theme, setTheme, forcedTheme, resolvedTheme, enableSystem, themes],
  );

  return (
    <ThemeContext.Provider value={providerValue}>
      <ThemeScript
        {...{
          forcedTheme,
          disableTransitionOnChange,
          enableSystem,
          enableColorScheme,
          storageKey,
          themes: themes!,
          defaultTheme,
          attribute,
          value,
          children,
          nonce,
        }}
      />
      {children}
    </ThemeContext.Provider>
  );
};

const ThemeScript = React.memo(
  ({
    forcedTheme,
    storageKey,
    attribute,
    enableSystem,
    enableColorScheme,
    defaultTheme,
    value,
    themes,
    nonce,
  }: ThemeProviderProps & { themes: string[] }) => {
    const scriptArgs = JSON.stringify([
      attribute,
      storageKey,
      defaultTheme,
      forcedTheme,
      themes,
      value,
      enableSystem,
      enableColorScheme,
    ]);

    return (
      <script
        nonce={nonce}
        dangerouslySetInnerHTML={{
          __html: `(${optimization.toString()})(${scriptArgs})`,
        }}
      />
    );
  },
);

const optimization = (
  attribute: string,
  storageKey: string,
  defaultTheme: string,
  forcedTheme: string,
  themes: string[],
  value: { [key: string]: string },
  enableSystem: boolean,
  enableColorScheme: boolean,
) => {
  const el = document.documentElement;
  const systemThemes = ["light", "dark"];
  const isClass = attribute === "class";
  const classes = isClass && value ? themes.map((t) => value[t] || t) : themes;

  function updateDOM(theme: string) {
    const name = value ? value[theme] || theme : theme;

    if (isClass) {
      el.classList.remove(...classes);
      el.classList.add(name);
    } else {
      el.setAttribute(attribute, name);
    }

    if (enableColorScheme) {
      if (systemThemes.includes(theme)) {
        el.style.colorScheme = theme;
      }
    }
  }

  function getSystemTheme() {
    return window.matchMedia("(prefers-color-scheme: dark)").matches
      ? "dark"
      : "light";
  }

  if (forcedTheme) {
    updateDOM(forcedTheme);
  } else {
    try {
      const theme = localStorage.getItem(storageKey) || defaultTheme;
      const isSystem = theme === "system";

      if (isSystem && enableSystem) {
        updateDOM(getSystemTheme());
      } else {
        updateDOM(theme);
      }
    } catch (e) {}
  }
};

const getTheme = (key: string, fallback?: string) => {
  if (typeof window === "undefined") return undefined;
  let theme;
  try {
    theme = localStorage.getItem(key) || undefined;
  } catch (e) {}
  return theme || fallback;
};

const getSystemTheme = (e?: MediaQueryList | MediaQueryListEvent) => {
  if (!e) e = window.matchMedia("(prefers-color-scheme: dark)");
  const isDark = e.matches;
  return isDark ? "dark" : "light";
};

