          "border-green-200 bg-green-50 text-green-800 dark:border-green-700 dark:bg-green-950/30 dark:text-green-200 [&>svg]:text-green-600 dark:[&>svg]:text-green-400",
        info: "border-blue-200 bg-blue-50 text-blue-800 dark:border-blue-700 dark:bg-blue-950/30 dark:text-blue-200 [&>svg]:text-blue-600 dark:[&>svg]:text-blue-400",
      },
    },
    defaultVariants: {
      tone: "default",
    },
  }
);

function AlertRoot({
  className,
  tone,
  ...props
}: MotionProps &
  VariantProps<typeof alertVariants> & {
    className?: string | string[];
  }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: -20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -20 }}
      transition={{ duration: 0.15, ease: "easeOut" }}
      data-slot="alert"
      role="alert"
      className={cn(alertVariants({ tone }), className)}
      {...props}
    />
  );
}

function AlertTitle({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="alert-title"
      className={cn(
        "col-start-2 line-clamp-1 min-h-4 font-medium tracking-tight",
        className
      )}
      {...props}
    />
  );
}

function AlertDescription({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="alert-description"
      className={cn(
        "text-muted-foreground col-start-2 grid justify-items-start gap-1 text-sm [&_p]:leading-relaxed",
        className
      )}
      {...props}
    />
  );
}

interface AlertProps extends VariantProps<typeof alertVariants> {
  title?: string;
  message?: string;
  children?: React.ReactNode;
  icon?: React.ReactNode;
  className?: string;
  canClosed?: boolean;
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
}

function Alert({
  tone,
  title,
  message,
  children,
  icon,
  className,
  canClosed = false,
  open: controlledOpen,
  onOpenChange: controlledSetOpen,
}: AlertProps) {
  const [internalOpen, setInternalOpen] = React.useState(true);

  const isControlled =
    controlledOpen !== undefined && controlledSetOpen !== undefined;

  const open = isControlled ? controlledOpen : internalOpen;
  const setOpen = isControlled ? controlledSetOpen : setInternalOpen;

  return (
    <AnimatePresence>
      {open && (
        <AlertRoot
          tone={tone}
          className={cn("flex w-full items-start gap-2", className)}
        >
          {icon && <div className="shrink-0">{icon}</div>}

          <div className="flex-1">
            {title && <AlertTitle>{title}</AlertTitle>}
            {children
              ? children
              : message && <AlertDescription>{message}</AlertDescription>}
          </div>

          {canClosed && (
            <Button
              onClick={() => setOpen(false)}
              iconOnly
              size="xs"
              tone="ghost"
              className="m-auto"
              aria-label="Close alert"
            >
              <X className="size-4" />
            </Button>
          )}
        </AlertRoot>
      )}
    </AnimatePresence>
  );
}

export type { AlertProps };
export { AlertRoot, Alert, AlertTitle, AlertDescription };

