function CommandList({
  className,
  children,
  ...props
}: React.ComponentProps<typeof Menu>) {
  const { items, onAction } = useCommandContext();

  return (
    <Menu
      items={items}
      aria-label={props["aria-label"] || "group"}
      onAction={onAction}
      renderEmptyState={() => <CommandEmpty />}
      className={cn(
