"use client";

import { X, Menu } from "lucide-react";
import * as React from "react";
import { useEffect, useRef } from "react";
import type {
  HeadingProps,
  TextProps,
  DialogTriggerProps as DialogPrimitiveProps,
  ModalOverlayProps as DialogOverlayPrimitiveProps,
} from "react-aria-components";
import {
  Dialog as DialogContentPrimitive,
  DialogTrigger as DialogPrimitive,
  ModalOverlay as DialogOverlayPrimitive,
  Button as ButtonPrimitive,
  Heading,
  Modal,
  Text,
} from "react-aria-components";
import { cn } from "@/lib/utils";
import { Button, type ButtonProps } from "@/components/ui/core/button";

const sizes = {
  xs: "sm:max-w-xs",
  sm: "sm:max-w-sm",
  md: "sm:max-w-md",
  lg: "sm:max-w-lg",
  xl: "sm:max-w-xl",
  "2xl": "sm:max-w-2xl",
  "3xl": "sm:max-w-3xl",
  "4xl": "sm:max-w-4xl",
  "5xl": "sm:max-w-5xl",
  full: "max-w-full",
};

function Dialog({ children, ...props }: DialogPrimitiveProps) {
  return <DialogPrimitive {...props}>{children}</DialogPrimitive>;
}

type DialogTriggerProps = ButtonProps;

const DialogTrigger = React.forwardRef<HTMLButtonElement, DialogTriggerProps>(
  ({ children, ...props }, ref) => {
    return (
      <Button ref={ref} {...props}>
        {children ? children : <Menu />}
      </Button>
    );
  },
);
DialogTrigger.displayName = "DialogTrigger";

interface DialogModalProps extends React.ComponentProps<typeof Modal> {
  size?: keyof typeof sizes;
}

function DialogModal({ size = "lg", children }: DialogModalProps) {
  return (
    <Modal
      className={({ isExiting, isEntering }) =>
        cn(
          "row-start-2 w-full text-left align-middle",
          "[--visual-viewport-vertical-padding:16px] sm:[--visual-viewport-vertical-padding:32px]",
          "relative bg-popover text-popover-foreground",
          "shadow-lg ring ring-foreground/5 dark:ring-border",
          "rounded-t-2xl md:rounded-xl",
          sizes[size],
          isEntering && [
            "slide-in-from-bottom animate-in duration-300 ease-out",
            "md:fade-in md:zoom-in-95 md:slide-in-from-bottom-0",
          ],
          isExiting && [
            "slide-out-to-bottom animate-out",
            "md:fade-out md:zoom-out-95 md:slide-out-to-bottom-0",
          ],
        )
      }
    >
      {children}
    </Modal>
  );
}

interface DialogContentProps extends React.ComponentProps<
  typeof DialogContentPrimitive
> {
  size?: keyof typeof sizes;
  isBlurred?: boolean;
  isDismissable?: boolean;
}

function DialogContent({
  role = "dialog",
  isDismissable,
  isBlurred,
  size = "lg",
  className,
  ...props
}: DialogContentProps) {
  return (
    <DialogOverlay isDismissable={isDismissable} isBlurred={isBlurred}>
      <DialogModal size={size}>
        <DialogContentPrimitive
          role={role}
          className={cn(
            "peer/dialog group/dialog bg-popover text-popover-foreground flex flex-col w-full gap-8 rounded-lg border p-6 shadow-lg duration-200",
            className,
          )}
          {...props}
        >
          {props.children}
        </DialogContentPrimitive>
      </DialogModal>
    </DialogOverlay>
  );
}

interface DialogOverlayProps extends DialogOverlayPrimitiveProps {
  isBlurred?: boolean;
}

function DialogOverlay({
  className,
  isDismissable = true,
  isBlurred = false,
  ...props
}: DialogOverlayProps) {
  return (
    <DialogOverlayPrimitive
      isDismissable={isDismissable}
      className={({ isExiting, isEntering }) =>
        cn(
          "fixed inset-0 z-50 h-(--visual-viewport-height,100vh) bg-black/30 md:p-4",
          "grid grid-rows-[1fr_auto] justify-items-center sm:grid-rows-[1fr_auto_3fr]",
          isEntering && "fade-in animate-in duration-300",
          isExiting && "fade-out animate-out duration-200",
          isBlurred && "backdrop-blur-sm backdrop-filter",
          className,
        )
      }
      {...props}
    />
  );
}

interface DialogHeaderProps extends Omit<React.ComponentProps<"div">, "title"> {
  title?: string;
  description?: string;
}

function DialogHeader({ className, ...props }: DialogHeaderProps) {
  const headerRef = useRef<HTMLHeadingElement>(null);

  useEffect(() => {
    const header = headerRef.current;
    if (!header) {
      return;
    }

    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        header.parentElement?.style.setProperty(
          "--dialog-header-height",
          `${entry.target.clientHeight}px`,
        );
      }
    });

    observer.observe(header);
    return () => observer.unobserve(header);
  }, []);

  return (
    <div
      data-slot="dialog-header"
      ref={headerRef}
      className={cn(
        "relative flex flex-col gap-2 text-center sm:text-start",
        className,
      )}
    >
      {props.title && <DialogTitle>{props.title}</DialogTitle>}
      {props.description && (
        <DialogDescription>{props.description}</DialogDescription>
      )}
      {!props.title && typeof props.children === "string" ? (
        <DialogTitle {...props} />
      ) : (
        props.children
      )}
    </div>
  );
}

interface DialogTitleProps extends HeadingProps {
  ref?: React.Ref<HTMLHeadingElement>;
}

function DialogTitle({ className, ref, ...props }: DialogTitleProps) {
  return (
    <Heading
      slot="title"
      ref={ref}
      className={cn(
        "text-balance font-semibold text-foreground text-lg/6 sm:text-base/6",
        className,
      )}
      {...props}
    />
  );
}

interface DialogDescriptionProps extends TextProps {
  ref?: React.Ref<HTMLDivElement>;
}

function DialogDescription({
  className,
  ref,
  ...props
}: DialogDescriptionProps) {
  return (
    <Text
      slot="description"
      className={cn(
        "text-pretty text-base/6 text-muted-foreground group-disabled:opacity-50",
        className,
      )}
      ref={ref}
      {...props}
    />
  );
}

function DialogBody({ className, ref, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="dialog-body"
      ref={ref}
      className={cn(
        "flex flex-col gap-4 max-h-[calc(var(--visual-viewport-height)-(var(--dialog-header-height)+var(--dialog-footer-height))*2)] overflow-auto",
        className,
      )}
      {...props}
    />
  );
}

function DialogFooter({ className, ...props }: React.ComponentProps<"div">) {
  const footerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const footer = footerRef.current;

    if (!footer) {
      return;
    }

    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        footer.parentElement?.style.setProperty(
          "--dialog-footer-height",
          `${entry.target.clientHeight}px`,
        );
      }
    });

    observer.observe(footer);
    return () => {
      observer.unobserve(footer);
    };
  }, []);
  return (
    <div
      ref={footerRef}
      data-slot="dialog-footer"
      className={cn(
        "flex flex-col-reverse gap-2 sm:flex-row sm:justify-end",
        className,
      )}
      {...props}
    />
  );
}

const DialogClose = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ children, className, tone = "outline", ...props }, ref) => {
    return (
      <Button
        slot="close"
        className={className}
        ref={ref}
        tone={tone}
        {...props}
      >
        {children ? children : "Close"}
      </Button>
    );
  },
);
DialogClose.displayName = "DialogClose";

interface DialogCloseIconProps extends Omit<ButtonProps, "children"> {
  className?: string;
  isDismissable?: boolean | undefined;
}

function DialogCloseIcon({ className, ...props }: DialogCloseIconProps) {
  return props.isDismissable ? (
    <Button
      tone="ghost"
      aria-label="Close"
      slot="close"
      className={cn(
        className,
        "close absolute top-1 end-1 z-50 flex flex-col size-8 place-content-center rounded-xl hover:bg-secondary focus:bg-secondary focus:outline-hidden focus-visible:ring-1 focus-visible:ring-primary sm:top-2 sm:end-2 sm:size-7 sm:rounded-md",
      )}
    >
      <X className="size-4" />
    </Button>
  ) : null;
}

export type {
  DialogTriggerProps,
  DialogContentProps,
  DialogOverlayProps,
  DialogHeaderProps,
  DialogTitleProps,
  DialogDescriptionProps,
  DialogCloseIconProps,
};

export {
  Dialog,
  DialogContent,
  DialogOverlay,
  DialogClose,
  DialogTrigger,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogBody,
  DialogFooter,
  DialogCloseIcon,
};

"use client";

import {
  Button,
  Disclosure as DisclosurePrimitive,
  DisclosureStateContext,
  Heading,
} from "react-aria-components";
import { ChevronDown } from "lucide-react";
import React, { use, useRef, createContext, useContext } from "react";
import { cn } from "@/lib/utils";
import { cva, type VariantProps } from "class-variance-authority";
import {
  AnimatePresence,
  motion,
  MotionConfig,
  type Transition,
  type Variants,
} from "motion/react";
import { type ButtonProps } from "@/components/ui/core/button";

const DisclosureStyleContext = createContext<
  VariantProps<typeof disclosureVariants>
>({
  tone: "default",
  size: "sm",
});

const useDisclosureStyle = () => useContext(DisclosureStyleContext);

const disclosureVariants = cva("w-full", {
  variants: {
    tone: {
      default: "border-b border-border",
      ghost: "",
      outline: [
        "border rounded-xl",
        "group-data-[tone=outline]:border-b group-data-[tone=outline]:border-border group-data-[tone=outline]:rounded-none",
      ],
      solid: [
        "border bg-background shadow-sm rounded-xl",
        "group-data-[tone=solid]:border-b group-data-[tone=solid]:border-border group-data-[tone=solid]:rounded-none",
      ],
      muted: [
        "border border-border bg-muted/50 rounded-xl",
        "group-data-[tone=muted]:border-b group-data-[tone=muted]:border-border group-data-[tone=muted]:rounded-none",
      ],
      separated: "border-t last:border-b",
    },
    size: {
      sm: "text-sm",
      md: "text-base",
      lg: "text-lg",
      xl: "text-xl",
      full: "",
    },
  },
  defaultVariants: {
    tone: "default",
    size: "sm",
  },
});

const disclosureTriggerVariants = cva(
  "flex items-center justify-between w-full font-medium transition-all focus:outline-hidden disabled:pointer-events-none disabled:opacity-50 cursor-pointer text-left",
  {
    variants: {
      size: {
        sm: "px-4 py-3",
        md: "px-5 py-4",
        lg: "px-6 py-5",
        xl: "px-7 py-6",
        full: "px-4 py-3",
      },
    },
    defaultVariants: {
      size: "sm",
    },
  }
);

const disclosureContentVariants = cva("overflow-hidden text-muted-foreground", {
  variants: {
    size: {
      sm: "px-4 pb-3",
      md: "px-5 pb-4",
      lg: "px-6 pb-5",
      xl: "px-7 pb-6",
      full: "px-4 pb-3",
    },
  },
  defaultVariants: {
    size: "sm",
  },
});

type DisclosureProps = React.ComponentProps<typeof DisclosurePrimitive> &
  VariantProps<typeof disclosureVariants> & {
    transition?: Transition;
  };

function Disclosure({
  tone,
  size,
  className,
  transition,
  ...props
}: DisclosureProps) {
  return (
    <DisclosureStyleContext.Provider value={{ tone, size }}>
      <MotionConfig transition={transition}>
        <DisclosurePrimitive
          className={cn(disclosureVariants({ tone, size }), className)}
          {...props}
        />
      </MotionConfig>
    </DisclosureStyleContext.Provider>
  );
}

interface DisclosureTriggerProps extends ButtonProps {
  icon?: React.ReactNode;
  hideChevron?: boolean;
  asChild?: boolean;
  children?: React.ReactNode | ButtonProps["children"];
}

function DisclosureTrigger({
  className,
  icon,
  hideChevron = false,
  asChild = false,
  children,
  ...props
}: DisclosureTriggerProps) {
  const { size } = useDisclosureStyle();
  const { isExpanded } = use(DisclosureStateContext)!;

  if (asChild) {
    if (!React.isValidElement(children)) {
      console.warn(
        "DisclosureTrigger with asChild expects a single React element as child."
      );
      return <>{children}</>;
    }

    return React.cloneElement(children, {
      slot: "trigger",
      ...props,
    });
  }

  return (
    <Heading>
      <Button
        slot="trigger"
        className={cn(disclosureTriggerVariants({ size }), className)}
        {...props}
      >
        {(values) => (
          <>
            {typeof children === "function" ? (
              children(values)
            ) : (
              <div className="flex items-center gap-2">
                {icon && <span className="shrink-0">{icon}</span>}
                <span className="text-left hover:underline transition-all duration-200">
                  {children}
                </span>
              </div>
            )}
            {!hideChevron && (
              <ChevronDown
                data-slot="disclosure-chevron"
                className={cn(
                  "size-4 shrink-0 transition duration-300",
                  isExpanded && "rotate-180"
                )}
              />
            )}
          </>
        )}
      </Button>
    </Heading>
  );
}

function DisclosureContent({
  className,
  children,
}: React.ComponentProps<"div">) {
  const { size } = useDisclosureStyle();
  const { isExpanded } = use(DisclosureStateContext)!;
  const contentRef = useRef<HTMLDivElement>(null);

  const variants: Variants = {
    expanded: {
      height: "auto",
      opacity: 1,
      transition: {
        duration: 0.3,
        ease: "easeInOut",
      },
    },
    collapsed: {
      height: 0,
      opacity: 0,
      transition: {
        duration: 0.3,
        ease: "easeInOut",
      },
    },
  };

  return (
    <AnimatePresence initial={false}>
      {isExpanded && (
        <motion.div
          initial="collapsed"
          animate="expanded"
          exit="collapsed"
          variants={variants}
          className={cn("overflow-hidden", className)}
        >
          <div
            ref={contentRef}
            className={cn(disclosureContentVariants({ size }), className)}
          >
            {children}
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

export { Disclosure, DisclosureTrigger, DisclosureContent };
export type { DisclosureProps, DisclosureTriggerProps };

import { use } from "react";
