"use client";

import React from "react";
import { type Easing, motion } from "motion/react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";

const circleVariants = cva("rounded-full inline-block flex-shrink-0", {
  variants: {
    size: {
      xs: "h-1.5 w-1.5",
      sm: "h-2 w-2",
      md: "h-4 w-4",
      lg: "h-6 w-6",
      xl: "h-8 w-8",
    },
    tone: {
      primary: "bg-primary",
      secondary: "bg-secondary",
      muted: "bg-muted",
      destructive: "bg-destructive",
      success: "bg-green-500",
      warning: "bg-yellow-500",
      info: "bg-blue-500",
      neutral: "bg-foreground",
      accent: "bg-accent",
      card: "bg-card",
    },
  },
  defaultVariants: {
    size: "md",
    tone: "neutral",
  },
});

const overlayVariants = cva("absolute rounded-full", {
  variants: {
    tone: {
      primary: "bg-primary/80",
      secondary: "bg-secondary/80",
      muted: "bg-muted/80",
      destructive: "bg-destructive/80",
      success: "bg-green-500/80",
      warning: "bg-yellow-500/80",
      info: "bg-blue-500/80",
      neutral: "bg-foreground/80",
      accent: "bg-accent/80",
      card: "bg-card/80",
    },
  },
});

type AnimationVariant =
  | "none"
  | "pulseTransparent"
  | "scale"
  | "shimmer"
  | "ripple"
  | "glow"
  | "breathe"
  | "vibrate"
  | "rotate"
  | "pulseSolid"
  | "bounce"
  | "swing"
  | "flash"
  | "fadeInOut";

interface AnimatedCircleIndicatorProps
  extends VariantProps<typeof circleVariants> {
  animation?: AnimationVariant;
  duration?: number;
  repeat?: number | "infinite";
  easing?: Easing | Easing[];
  as?: React.ElementType;
  className?: string;
  style?: React.CSSProperties;
  overlay?: boolean;
}

function AnimatedCircleIndicator({
  size = "sm",
  tone = "neutral",
  animation = "none",
  duration = 1.5,
  repeat = "infinite",
  easing = "easeInOut",
  as = "span",
  className,
  style,
  overlay = false,
}: AnimatedCircleIndicatorProps) {
  const Component = motion(as);

  const getAnimationConfig = () => {
    const baseConfig = {
      transition: {
        duration,
        repeat: repeat === "infinite" ? Infinity : repeat,
        ease: easing,
      },
    };

    switch (animation) {
      case "scale":
        return {
          initial: { scale: 1 },
          animate: { scale: [1, 1.2, 1] },
          ...baseConfig,
        };

      case "shimmer":
        return {
          initial: { opacity: 1 },
          animate: { opacity: [1, 0.3, 1] },
          transition: {
            ...baseConfig.transition,
            times: [0, 0.5, 1],
          },
        };

      case "ripple":
        return {
          initial: { scale: 0.8, opacity: 1 },
          animate: {
            scale: [0.8, 1.4, 0.8],
            opacity: [1, 0, 1],
          },
          ...baseConfig,
        };

      case "glow":
        return {
          initial: { boxShadow: "0 0 0px rgba(255,255,255,0)" },
          animate: {
            boxShadow: [
              "0 0 0px rgba(255,255,255,0)",
              "0 0 12px rgba(255,255,255,0.8)",
              "0 0 0px rgba(255,255,255,0)",
            ],
          },
          ...baseConfig,
        };

      case "breathe":
        return {
          initial: { scale: 1, opacity: 1 },
          animate: {
            scale: [1, 1.15, 1],
            opacity: [1, 0.7, 1],
          },
          ...baseConfig,
        };

      case "vibrate":
        return {
          initial: { x: 0 },
          animate: { x: [-1, 1, -1, 1, 0] },
          transition: {
            ...baseConfig.transition,
            duration: 0.3,
          },
        };

      case "rotate":
        return {
          initial: { rotate: 0 },
          animate: { rotate: 360 },
          transition: {
            duration: duration * 2,
            repeat: repeat === "infinite" ? Infinity : repeat,
            ease: "linear",
          },
        };

      case "pulseSolid":
        return {
          initial: { opacity: 1 },
          animate: { opacity: [1, 0.5, 1] },
          ...baseConfig,
        };

      case "bounce":
        return {
          initial: { y: 0 },
          animate: { y: [-4, 0, -4] },
          ...baseConfig,
        };

      case "swing":
        return {
          initial: { rotate: 0 },
          animate: { rotate: [-15, 15, -15] },
          ...baseConfig,
        };

      case "flash":
        return {
          initial: { opacity: 1 },
          animate: { opacity: [1, 0.2, 1, 0.2, 1] },
          transition: {
            ...baseConfig.transition,
            duration: 1,
          },
        };

      case "fadeInOut":
        return {
          initial: { opacity: 0 },
          animate: { opacity: [0, 1, 0] },
          ...baseConfig,
        };

      default:
        return {};
    }
  };

  const animationConfig = getAnimationConfig();
  const shouldRenderOverlay = animation === "pulseTransparent" || overlay;

  return (
    <Component
      className={cn("relative", circleVariants({ size, tone }), className)}
      style={style}
      {...(animation !== "none" ? animationConfig : {})}
    >
      {shouldRenderOverlay && animation === "pulseTransparent" && (
        <motion.span
          className={cn(
            "absolute inset-0 rounded-full",
            overlayVariants({ tone })
          )}
          initial={{ scale: 1, opacity: 1 }}
          animate={{
            scale: [1, 1.8, 1],
            opacity: [0.6, 0, 0.6],
          }}
          transition={{
            duration,
            repeat: repeat === "infinite" ? Infinity : repeat,
            ease: easing,
          }}
        />
      )}
    </Component>
  );
}

export { AnimatedCircleIndicator, type AnimatedCircleIndicatorProps };

"use client";

import {
  motion,
  MotionValue,
  useMotionValue,
  useSpring,
  useTransform,
  type SpringOptions,
  AnimatePresence,
} from "motion/react";
import {
  Children,
  cloneElement,
  createContext,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import { cn } from "@/lib/utils";

const AnimatedDOCK_HEIGHT = 128;
const DEFAULT_MAGNIFICATION = 80;
const DEFAULT_DISTANCE = 150;
const DEFAULT_PANEL_HEIGHT = 64;

type AnimatedDockProps = {
  children: React.ReactNode;
  className?: string;
  distance?: number;
  panelHeight?: number;
  magnification?: number;
  spring?: SpringOptions;
};

type AnimatedDockItemProps = {
  className?: string;
  children: React.ReactNode;
  onClick?: () => void;
};

type AnimatedDockLabelProps = {
  className?: string;
  children: React.ReactNode;
};

type AnimatedDockIconProps = {
  className?: string;
  children: React.ReactNode;
};

type AnimatedDockContextType = {
  mouseX: MotionValue;
  spring: SpringOptions;
  magnification: number;
  distance: number;
};

type AnimatedDockProviderProps = {
  children: React.ReactNode;
  value: AnimatedDockContextType;
};

const AnimatedDockContext = createContext<AnimatedDockContextType | undefined>(
  undefined
);

function AnimatedDockProvider({ children, value }: AnimatedDockProviderProps) {
  return (
    <AnimatedDockContext.Provider value={value}>
      {children}
    </AnimatedDockContext.Provider>
  );
}

function useAnimatedDock() {
  const context = useContext(AnimatedDockContext);
  if (!context) {
    throw new Error(
      "useAnimatedDock must be used within an AnimatedDockProvider"
    );
  }
  return context;
}

function AnimatedDock({
  children,
  className,
  spring = { mass: 0.1, stiffness: 150, damping: 12 },
  magnification = DEFAULT_MAGNIFICATION,
  distance = DEFAULT_DISTANCE,
  panelHeight = DEFAULT_PANEL_HEIGHT,
}: AnimatedDockProps) {
  const mouseX = useMotionValue(Infinity);
  const isHovered = useMotionValue(0);

  const maxHeight = useMemo(() => {
    return Math.max(AnimatedDOCK_HEIGHT, magnification + magnification / 2 + 4);
  }, [magnification]);

  const heightRow = useTransform(isHovered, [0, 1], [panelHeight, maxHeight]);
  const height = useSpring(heightRow, spring);

  return (
    <motion.div
      style={{
        height: height,
        scrollbarWidth: "none",
      }}
      className="mx-2 flex max-w-full items-end overflow-x-auto"
    >
      <motion.div
        onMouseMove={({ pageX }) => {
          isHovered.set(1);
          mouseX.set(pageX);
        }}
        onMouseLeave={() => {
          isHovered.set(0);
          mouseX.set(Infinity);
        }}
        className={cn(
          "mx-auto flex w-fit gap-4 rounded-xl bg-muted px-4",
          className
        )}
        style={{ height: panelHeight }}
        role="toolbar"
        aria-label="Application Animateddock"
      >
        <AnimatedDockProvider
          value={{ mouseX, spring, distance, magnification }}
        >
          {children}
        </AnimatedDockProvider>
      </motion.div>
    </motion.div>
  );
}

function AnimatedDockItem({
  children,
  className,
  onClick,
}: AnimatedDockItemProps) {
  const ref = useRef<HTMLDivElement>(null);

  const { distance, magnification, mouseX, spring } = useAnimatedDock();

  const isHovered = useMotionValue(0);

  const mouseDistance = useTransform(mouseX, (val) => {
    const domRect = ref.current?.getBoundingClientRect() ?? { x: 0, width: 0 };
    return val - domRect.x - domRect.width / 2;
  });

  const widthTransform = useTransform(
    mouseDistance,
    [-distance, 0, distance],
    [40, magnification, 40]
  );

  const width = useSpring(widthTransform, spring);

  return (
    <motion.div
      ref={ref}
      style={{ width }}
      onHoverStart={() => isHovered.set(1)}
      onHoverEnd={() => isHovered.set(0)}
      onFocus={() => isHovered.set(1)}
      onBlur={() => isHovered.set(0)}
      className={cn(
        "relative inline-flex items-center justify-center bg-muted",
        className
      )}
      tabIndex={0}
      role="button"
      aria-haspopup="true"
      onClick={onClick}
    >
      {Children.map(children, (child) =>
        cloneElement(child as React.ReactElement, { width, isHovered })
      )}
    </motion.div>
  );
}

function AnimatedDockLabel({
  children,
  className,
  ...rest
}: AnimatedDockLabelProps) {
  const restProps = rest as Record<string, unknown>;
  const isHovered = restProps["isHovered"] as MotionValue<number>;
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const unsubscribe = isHovered.on("change", (latest) => {
      setIsVisible(latest === 1);
    });

    return () => unsubscribe();
  }, [isHovered]);

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div
          initial={{ opacity: 0, y: 0 }}
          animate={{ opacity: 1, y: -10 }}
          exit={{ opacity: 0, y: 0 }}
          transition={{ duration: 0.2 }}
          className={cn(
            "absolute -top-6 left-1/2 w-fit whitespace-pre rounded-md border bg-primary text-primary-foreground px-2 py-0.5 text-xs",
            className
          )}
          role="tooltip"
          style={{ x: "-50%" }}
        >
          {children}
        </motion.div>
      )}
    </AnimatePresence>
  );
}

function AnimatedDockIcon({
  children,
  className,
  ...rest
}: AnimatedDockIconProps) {
  const restProps = rest as Record<string, unknown>;
  const width = restProps["width"] as MotionValue<number>;

  const widthTransform = useTransform(width, (val) => val / 2);

  return (
    <motion.div
      style={{ width: widthTransform }}
      className={cn("flex items-center justify-center", className)}
    >
      {children}
    </motion.div>
  );
}

export type {
  AnimatedDockProps,
  AnimatedDockItemProps,
  AnimatedDockLabelProps,
  AnimatedDockIconProps,
  AnimatedDockContextType,
  AnimatedDockProviderProps,
};
export { AnimatedDock, AnimatedDockIcon, AnimatedDockItem, AnimatedDockLabel };

"use client";

import { useState, useCallback, ReactNode } from "react";
import { motion } from "motion/react";
import { Power, PowerOff } from "lucide-react";
import { cn } from "@/lib/utils";

interface AnimatedSwitchProps {
  value?: boolean;
  defaultValue?: boolean;
  onValueChange?: (value: boolean) => void;
  className?: string;
  onIcon?: ReactNode;
  offIcon?: ReactNode;
}

function AnimatedSwitch({
  value,
  defaultValue = false,
  onValueChange,
  className,
  onIcon = <Power />,
  offIcon = <PowerOff />,
}: AnimatedSwitchProps) {
  const [internal, setInternal] = useState<boolean>(defaultValue);

  const isControlled = value !== undefined;
  const isOn = isControlled ? value : internal;

  const switching = useCallback(() => {
    const next = !isOn;
    if (!isControlled) setInternal(next);
    if (onValueChange) onValueChange(next);
  }, [isOn, isControlled, onValueChange]);

  return (
    <div
      onClick={switching}
      className={cn(
        "relative shrink-0 min-w-20 flex items-center cursor-pointer rounded-lg ring ring-border bg-card p-1",
        "w-20 h-10",
        className,
      )}
    >
      <div
        className={cn(
          "absolute inset-s-3 top-1/2 -translate-y-1/2 flex items-center justify-center pointer-events-none z-10",
          "size-4",
        )}
      >
        {offIcon}
      </div>

      <div
        className={cn(
          "absolute inset-e-[11.5px] top-1/2 -translate-y-1/2 flex items-center justify-center pointer-events-none z-10",
          "size-4",
        )}
      >
        {onIcon}
      </div>

      <motion.div
        layout
        transition={{
          type: "spring",
          stiffness: 500,
          damping: 35,
          mass: 0.8,
