import React, { useRef, useState, useCallback, useEffect } from "react";
import { motion, useSpring, useTransform, SpringOptions } from "motion/react";
import { cn } from "@/lib/utils";

type HoverGlowProps = {
  className?: string;
  size?: number;
  springOptions?: SpringOptions;
};

const HoverGlow = ({
  className,
  size = 200,
  springOptions = { bounce: 0 },
}: HoverGlowProps) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [isHovered, setIsHovered] = useState(false);
  const [parentElement, setParentElement] = useState<HTMLElement | null>(null);

  const mouseX = useSpring(0, springOptions);
  const mouseY = useSpring(0, springOptions);

  const glowLeft = useTransform(mouseX, (x) => `${x - size / 2}px`);
  const glowTop = useTransform(mouseY, (y) => `${y - size / 2}px`);

  useEffect(() => {
    if (containerRef.current) {
      const parent = containerRef.current.parentElement;
      if (parent) {
        parent.style.position = "relative";
        parent.style.overflow = "hidden";
        setParentElement(parent);
      }
    }
  }, []);

  const handleMouseMove = useCallback(
    (event: MouseEvent) => {
      if (!parentElement) return;
      const { left, top } = parentElement.getBoundingClientRect();
      mouseX.set(event.clientX - left);
      mouseY.set(event.clientY - top);
    },
    [mouseX, mouseY, parentElement]
  );

  useEffect(() => {
    if (!parentElement) return;

    const abortController = new AbortController();

    parentElement.addEventListener("mousemove", handleMouseMove, {
      signal: abortController.signal,
    });
    parentElement.addEventListener("mouseenter", () => setIsHovered(true), {
      signal: abortController.signal,
    });
    parentElement.addEventListener("mouseleave", () => setIsHovered(false), {
      signal: abortController.signal,
    });

    return () => {
      abortController.abort();
    };
  }, [parentElement, handleMouseMove]);

  return (
    <motion.div
      ref={containerRef}
      className={cn(
        "pointer-events-none absolute rounded-full bg-[radial-gradient(circle_at_center,var(--tw-gradient-stops),transparent_80%)] blur-2xl transition-opacity duration-200",
        "bg-primary",
        isHovered ? "opacity-100" : "opacity-0",
        className
      )}
      style={{
        width: size,
        height: size,
        left: glowLeft,
        top: glowTop,
      }}
    />
  );
};

export type { HoverGlowProps };
export { HoverGlow };

"use client";

import React, {
  useCallback,
  useContext,
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";
import {
  motion,
  AnimatePresence,
  MotionConfig,
  Transition,
  Variant,
  LayoutGroup,
} from "motion/react";
import { createPortal } from "react-dom";
import { cn } from "@/lib/utils";
import { XIcon } from "lucide-react";
import { useOutsideClick } from "@/hooks/use-outside-click";

type MorphingCardContextType = {
  isOpen: boolean;
  setIsOpen: React.Dispatch<React.SetStateAction<boolean>>;
  uniqueId: string;
  triggerRef: React.RefObject<HTMLButtonElement | null>;
};

const MorphingCardContext = React.createContext<MorphingCardContextType | null>(
  null
);

function useMorphingCard() {
  const context = useContext(MorphingCardContext);
  if (!context) {
    throw new Error(
      "useMorphingCard must be used within a MorphingCardProvider"
    );
  }
  return context;
}

type MorphingCardProviderProps = {
  children: React.ReactNode;
  transition?: Transition;
};

function MorphingCardProvider({
  children,
  transition,
}: MorphingCardProviderProps) {
  const [isOpen, setIsOpen] = useState(false);
  const uniqueId = useId();
  const triggerRef = useRef<HTMLButtonElement>(null!);

  const contextValue = useMemo(
    () => ({
      isOpen,
      setIsOpen,
      uniqueId,
      triggerRef,
    }),
    [isOpen, uniqueId]
  );

  return (
    <MorphingCardContext.Provider value={contextValue}>
      <MotionConfig transition={transition}>
        <LayoutGroup id={uniqueId}>{children}</LayoutGroup>
      </MotionConfig>
    </MorphingCardContext.Provider>
  );
}

type MorphingCardProps = {
  children: React.ReactNode;
  transition?: Transition;
};

function MorphingCard({ children, transition }: MorphingCardProps) {
  return (
    <MorphingCardProvider>
      <MotionConfig transition={transition}>{children}</MotionConfig>
    </MorphingCardProvider>
  );
}

type MorphingCardTriggerProps = {
  children: React.ReactNode;
  className?: string;
  style?: React.CSSProperties;
  triggerRef?: React.RefObject<HTMLButtonElement>;
};

function MorphingCardTrigger({
  children,
  className,
  style,
  triggerRef,
}: MorphingCardTriggerProps) {
  const { setIsOpen, isOpen, uniqueId } = useMorphingCard();

  const handleClick = useCallback(() => {
    setIsOpen(!isOpen);
  }, [isOpen, setIsOpen]);

  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent) => {
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        setIsOpen(!isOpen);
      }
    },
    [isOpen, setIsOpen]
  );

  return (
    <motion.button
      ref={triggerRef}
      layoutId={`card-${uniqueId}`}
      className={cn("relative cursor-pointer", className)}
      onClick={handleClick}
      onKeyDown={handleKeyDown}
      style={style}
      aria-haspopup="dialog"
      aria-expanded={isOpen}
      aria-controls={`morphing-card-content-${uniqueId}`}
      aria-label={`Open card ${uniqueId}`}
    >
      {children}
    </motion.button>
  );
}

interface MorphingCardContentRenderProps {
  setIsOpen: React.Dispatch<React.SetStateAction<boolean>>;
  isOpen: boolean;
}

type MorphingCardContentProps = {
  children:
    | React.ReactNode
    | ((props: MorphingCardContentRenderProps) => React.ReactNode);
  className?: string;
  style?: React.CSSProperties;
};

function MorphingCardContent({
  children,
  className,
  style,
}: MorphingCardContentProps) {
  const { setIsOpen, isOpen, uniqueId, triggerRef } = useMorphingCard();
  const containerRef = useRef<HTMLDivElement>(null!);
  const [firstFocusableElement, setFirstFocusableElement] =
    useState<HTMLElement | null>(null);
  const [lastFocusableElement, setLastFocusableElement] =
    useState<HTMLElement | null>(null);

  const content =
    typeof children === "function" ? children({ setIsOpen, isOpen }) : children;

  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        setIsOpen(false);
      }
      if (event.key === "Tab") {
        if (!firstFocusableElement || !lastFocusableElement) return;

        if (event.shiftKey) {
          if (document.activeElement === firstFocusableElement) {
            event.preventDefault();
            lastFocusableElement.focus();
          }
        } else {
          if (document.activeElement === lastFocusableElement) {
            event.preventDefault();
            firstFocusableElement.focus();
          }
        }
      }
    };

    document.addEventListener("keydown", handleKeyDown);
    return () => document.removeEventListener("keydown", handleKeyDown);
  }, [setIsOpen, firstFocusableElement, lastFocusableElement]);

  useEffect(() => {
    if (isOpen) {
      document.body.classList.add("overflow-hidden");
      const focusableElements = containerRef.current?.querySelectorAll(
        'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
      );
      if (focusableElements && focusableElements.length > 0) {
        setFirstFocusableElement(focusableElements[0] as HTMLElement);
        setLastFocusableElement(
          focusableElements[focusableElements.length - 1] as HTMLElement
        );
        (focusableElements[0] as HTMLElement).focus();
      }
    } else {
      document.body.classList.remove("overflow-hidden");
      triggerRef.current?.focus();
    }
  }, [isOpen, triggerRef]);

  useOutsideClick(containerRef, () => {
    if (isOpen) setIsOpen(false);
  });

  return (
    <motion.div
      ref={containerRef}
      layoutId={`card-${uniqueId}`}
      className={cn(
        "overflow-hidden bg-popover pointer-events-auto",
        className
      )}
      style={style}
      role="dialog"
      aria-modal="true"
      aria-labelledby={`morphing-card-title-${uniqueId}`}
      aria-describedby={`morphing-card-description-${uniqueId}`}
    >
      {content}
    </motion.div>
  );
}

type MorphingCardContainerProps = {
  children: React.ReactNode;
  className?: string;
  style?: React.CSSProperties;
  showOverlay?: boolean;
  overlay?: MorphingCardOverlayProps;
};

function MorphingCardContainer({
  children,
  showOverlay = true,
  overlay,
}: MorphingCardContainerProps) {
  const { isOpen } = useMorphingCard();
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    return () => setMounted(false);
  }, []);

  if (!mounted) return null;

  return createPortal(
    <AnimatePresence initial={false} mode="sync">
      {isOpen && (
        <>
          {showOverlay && <MorphingCardOverlay {...overlay} />}
          <div className="fixed inset-0 z-50 flex items-center justify-center pointer-events-none">
            {children}
          </div>
        </>
      )}
    </AnimatePresence>,
    document.body
  );
}

type MorphingCardOverlayProps = {
  className?: string;
  children?: React.ReactNode;
};

function MorphingCardOverlay({
  className,
  children,
}: MorphingCardOverlayProps) {
  const { uniqueId } = useMorphingCard();
  return (
    <motion.div
