import { useEffect, useState } from "react";
import { fetchSource, type SourceFile } from "@/lib/fetch-source";

type ComponentSourceState = {
  code: SourceFile["code"];
  loading: boolean;
};

export function useComponentSource(comp: string): ComponentSourceState {
  const [state, setState] = useState<ComponentSourceState>({
    code: "",
    loading: false,
  });

  useEffect(() => {
    if (!comp) {
      setState({ code: "", loading: false });
      return;
    }

    let active = true;

    const load = async () => {
      setState((s) => ({ ...s, loading: true }));

      try {
        const res = await fetchSource(comp);

        if (!active || !res?.files?.length) {
          setState({ code: "", loading: false });
          return;
        }

        const file = res.files[0];
        const code = file.code ?? file.content ?? "";

        setState({ code, loading: false });
      } catch {
        if (active) {
          setState({ code: "", loading: false });
        }
      }
    };

    load();

    return () => {
      active = false;
    };
  }, [comp]);

  return state;
}

"use client";

import * as React from "react";

export interface useCopyToClipboardProps {
  timeout?: number;
}

export function useCopyToClipboard({
  timeout = 2000,
}: useCopyToClipboardProps = {}) {
  const [isCopied, setIsCopied] = React.useState(false);

  const copyToClipboard = (value: string) => {
    if (typeof window === "undefined" || !value) {
      return;
    }

    if (!navigator?.clipboard) {
      console.warn("Clipboard not supported");
      return;
    }

    navigator.clipboard.writeText(value).then(() => {
      setIsCopied(true);

      setTimeout(() => {
        setIsCopied(false);
      }, timeout);
    });
  };

  return { isCopied, copyToClipboard };
}

"use client";

import {
  useCallback,
  useEffect,
  useRef,
  useState,
  type RefObject,
} from "react";
import { NAV_POSITIONS } from "@/constants/nav-positions";
import { useUiPreferences } from "@/hooks/use-ui-preferences";

export type NavPosition = "left" | "center" | "right";

interface UseFloatingNavOptions {
  scrollThreshold?: number;
}

interface UseFloatingNavResult {
  navRef: RefObject<HTMLDivElement | null>;
  isVisible: boolean;
  setVisible: (value: boolean) => void;
  showNav: () => void;
  hideNav: () => void;
  toggleNav: () => void;
  navPosition: NavPosition;
  positionClass: string;
  setNavPosition: (position: NavPosition) => void;
}

export function useFloatingNav({
  scrollThreshold = 5,
}: UseFloatingNavOptions = {}): UseFloatingNavResult {
  const navPosition = useUiPreferences((s) => s.navPosition as NavPosition);
  const setNavPosition = useUiPreferences(
    (s) => s.setNavPosition as (position: NavPosition) => void,
  );

  const [isVisible, setIsVisible] = useState<boolean>(true);
  const lastScrollY = useRef<number>(0);
  const navRef = useRef<HTMLDivElement | null>(null);

  const positionClass = NAV_POSITIONS[navPosition] ?? NAV_POSITIONS.center;

  const showNav = useCallback(() => {
    setIsVisible(true);
  }, []);

  const hideNav = useCallback(() => {
    setIsVisible(false);
  }, []);

  const toggleNav = useCallback(() => {
    setIsVisible((prev) => !prev);
  }, []);

  const setVisible = useCallback((value: boolean) => {
    setIsVisible(value);
  }, []);

  useEffect(() => {
    if (typeof window !== "undefined") {
      const customContainer = document.querySelector("[data-scrollable]");
      lastScrollY.current = customContainer
        ? (customContainer as HTMLElement).scrollTop
        : window.scrollY;
    }

    const handleScroll = (e: Event) => {
      const target = e.target as HTMLElement | Document | Window;
      let current = 0;
      let isTrackedScroll = false;

      if (target === document || target === window) {
        current = window.scrollY;
        isTrackedScroll = true;
      } else if (
        target instanceof HTMLElement &&
        target.hasAttribute("data-scrollable")
      ) {
        current = target.scrollTop;
        isTrackedScroll = true;
      }

      if (!isTrackedScroll) return;

      const diff = current - lastScrollY.current;

      if (diff > scrollThreshold) {
        hideNav();
      } else if (diff < -scrollThreshold) {
        showNav();
      }

      lastScrollY.current = current;
    };

    window.addEventListener("scroll", handleScroll, {
      passive: true,
      capture: true,
    });
    return () =>
      window.removeEventListener("scroll", handleScroll, { capture: true });
  }, [scrollThreshold, hideNav, showNav]);

  return {
    navRef,
    isVisible,
    setVisible,
    showNav,
    hideNav,
    toggleNav,
    navPosition,
    positionClass,
    setNavPosition,
  };
}

import { useCallback, useSyncExternalStore } from "react";

export function useIsMobile(breakpoint: number = 768): boolean {
  const subscribe = useCallback(
    (callback: () => void) => {
      if (typeof window === "undefined") return () => {};
      const mql = window.matchMedia(`(max-width: ${breakpoint - 1}px)`);
      mql.addEventListener("change", callback);
      return () => mql.removeEventListener("change", callback);
    },
    [breakpoint],
  );

  const getSnapshot = useCallback(() => {
    if (typeof window === "undefined") return false;
    return window.matchMedia(`(max-width: ${breakpoint - 1}px)`).matches;
  }, [breakpoint]);

  const getServerSnapshot = () => false;

  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

import { useEffect } from "react";

export function useOutsideClick(
  ref: React.RefObject<HTMLElement>,
  callback: (event: MouseEvent | TouchEvent) => void
) {
  useEffect(() => {
    const listener = (event: MouseEvent | TouchEvent) => {
      const el = ref.current;
      if (!el || el.contains(event.target as Node)) return;
      callback(event);
    };

    document.addEventListener("mousedown", listener);
    document.addEventListener("touchstart", listener);

    return () => {
      document.removeEventListener("mousedown", listener);
      document.removeEventListener("touchstart", listener);
    };
  }, [ref, callback]);
}

