interface MdxJsxAttribute extends Node {
  type: "mdxJsxAttribute";
  name: string;
  value: string | number | boolean | null | undefined;
}

interface MdxJsxFlowElement extends Parent {
  type: "mdxJsxFlowElement";
  name: string | null;
  attributes: MdxJsxAttribute[];
}

